#include "audio_decoder.hpp"
#include <QDebug>
#include <QtConcurrent>
#include <algorithm>

namespace AviQtl::Core {

AudioDecoder::AudioDecoder(int clipId, const QUrl &source, QObject *parent) : MediaDecoder(clipId, source, parent) {
    // 生成とデコード開始を分離: 呼び出し元が scheduleStart() を呼ぶ
}

AudioDecoder::~AudioDecoder() {
    m_closing.store(true, std::memory_order_release);
    if (m_decodeFuture.isRunning()) {
        m_decodeFuture.waitForFinished();
    }
    closeFFmpeg();
}

void AudioDecoder::startDecoding() {
    // UIスレッドをブロックしないようバックグラウンドで全デコード
    m_decodeFuture = QtConcurrent::run([this] -> void {
        closeFFmpeg();
        m_isReady = false;

        QString path = m_source.toLocalFile();
        if (path.isEmpty()) {
            path = m_source.toString();
        }

        if (avformat_open_input(&m_fmtCtx, path.toStdString().c_str(), nullptr, nullptr) < 0) {
            qWarning() << "[AudioDecoder] avformat_open_input failed:" << path;
            m_isReady = true;
            emit ready();
            return;
        }

        avformat_find_stream_info(m_fmtCtx, nullptr);

        m_streamIdx = av_find_best_stream(m_fmtCtx, AVMEDIA_TYPE_AUDIO, -1, -1, nullptr, 0);
        if (m_streamIdx < 0) {
            qWarning() << "[AudioDecoder] 音声ストリームが見つかりません:" << path;
            m_isReady = true;
            emit ready();
            return;
        }
        m_stream = m_fmtCtx->streams[m_streamIdx];

        const AVCodec *codec = avcodec_find_decoder(m_stream->codecpar->codec_id);
        if (!codec) {
            qWarning() << "[AudioDecoder] 対応コーデックが見つかりません";
            m_isReady = true;
            emit ready();
            return;
        }

        m_decCtx = avcodec_alloc_context3(codec);
        avcodec_parameters_to_context(m_decCtx, m_stream->codecpar);
        if (avcodec_open2(m_decCtx, codec, nullptr) < 0) {
            qWarning() << "[AudioDecoder] avcodec_open2 failed";
            m_isReady = true;
            emit ready();
            return;
        }

        // swresample: デコード出力 → Float32 ステレオ へ変換
        m_swrCtx = swr_alloc();
        av_opt_set_chlayout(m_swrCtx, "in_chlayout", &m_decCtx->ch_layout, 0);
        av_opt_set_int(m_swrCtx, "in_sample_rate", m_decCtx->sample_rate, 0);
        av_opt_set_sample_fmt(m_swrCtx, "in_sample_fmt", m_decCtx->sample_fmt, 0);
        AVChannelLayout stereo = AV_CHANNEL_LAYOUT_STEREO;
        av_opt_set_chlayout(m_swrCtx, "out_chlayout", &stereo, 0);
        av_opt_set_int(m_swrCtx, "out_sample_rate", m_sampleRate, 0);
        av_opt_set_sample_fmt(m_swrCtx, "out_sample_fmt", AV_SAMPLE_FMT_FLT, 0);
        swr_init(m_swrCtx);

        m_frame = av_frame_alloc();
        m_pkt = av_packet_alloc();

        // インターリーブ Float32 ステレオ バッファ
        std::vector<float> convertBuf;

        while (av_read_frame(m_fmtCtx, m_pkt) >= 0) {
            if (m_closing.load(std::memory_order_acquire)) {
                av_packet_unref(m_pkt);
                break;
            }
            if (m_pkt->stream_index != m_streamIdx) {
                av_packet_unref(m_pkt);
                continue;
            }

            if (avcodec_send_packet(m_decCtx, m_pkt) < 0) {
                av_packet_unref(m_pkt);
                continue;
            }
            av_packet_unref(m_pkt);

            while (avcodec_receive_frame(m_decCtx, m_frame) == 0) {
                // 変換後サンプル数を算出（切り上げ）
                int outSamples = static_cast<int>(av_rescale_rnd(m_frame->nb_samples, m_sampleRate, m_decCtx->sample_rate, AV_ROUND_UP));

                // Float32 ステレオ = 1サンプル × 2ch
                convertBuf.resize(static_cast<size_t>(outSamples) * 2);
                auto *outPtr = reinterpret_cast<uint8_t *>(convertBuf.data());

                int converted = swr_convert(m_swrCtx, &outPtr, outSamples, const_cast<const uint8_t **>(m_frame->data), m_frame->nb_samples);

                if (converted > 0) {
                    QMutexLocker locker(&m_mutex);
                    m_fullAudioData.insert(m_fullAudioData.end(), convertBuf.begin(), convertBuf.begin() + static_cast<ptrdiff_t>(converted) * 2);
                }
                av_frame_unref(m_frame);
            }
        }

        // デコーダフラッシュ（末尾フレームを取りこぼさない）
        avcodec_send_packet(m_decCtx, nullptr);
        while (avcodec_receive_frame(m_decCtx, m_frame) == 0) {
            int outSamples = static_cast<int>(av_rescale_rnd(m_frame->nb_samples, m_sampleRate, m_decCtx->sample_rate, AV_ROUND_UP));
            convertBuf.resize(static_cast<size_t>(outSamples) * 2);
            auto *outPtr = reinterpret_cast<uint8_t *>(convertBuf.data());
            int converted = swr_convert(m_swrCtx, &outPtr, outSamples, const_cast<const uint8_t **>(m_frame->data), m_frame->nb_samples);
            if (converted > 0) {
                QMutexLocker locker(&m_mutex);
                m_fullAudioData.insert(m_fullAudioData.end(), convertBuf.begin(), convertBuf.begin() + static_cast<ptrdiff_t>(converted) * 2);
            }
            av_frame_unref(m_frame);
        }

        // swrフラッシュ（リサンプラー内部バッファを吐き出す）
        int remaining = static_cast<int>(swr_get_delay(m_swrCtx, m_sampleRate) + 1);
        if (remaining > 0) {
            convertBuf.resize(static_cast<size_t>(remaining) * 2);
            auto *outPtr = reinterpret_cast<uint8_t *>(convertBuf.data());
            int flushed = swr_convert(m_swrCtx, &outPtr, remaining, nullptr, 0);
            if (flushed > 0) {
                QMutexLocker locker(&m_mutex);
                m_fullAudioData.insert(m_fullAudioData.end(), convertBuf.begin(), convertBuf.begin() + static_cast<ptrdiff_t>(flushed) * 2);
            }
        }

        buildPeakCache();

        qDebug() << "[AudioDecoder] clip" << m_clipId << "decoded. total samples:" << m_fullAudioData.size();
        m_isReady = true;
        emit ready();
    });
}

void AudioDecoder::closeFFmpeg() {
    if (m_frame != nullptr) {
        av_frame_free(&m_frame);
        m_frame = nullptr;
    }
    if (m_pkt != nullptr) {
        av_packet_free(&m_pkt);
        m_pkt = nullptr;
    }
    if (m_swrCtx != nullptr) {
        swr_free(&m_swrCtx);
        m_swrCtx = nullptr;
    }
    if (m_decCtx != nullptr) {
        avcodec_free_context(&m_decCtx);
        m_decCtx = nullptr;
    }
    if (m_fmtCtx != nullptr) {
        avformat_close_input(&m_fmtCtx);
        m_fmtCtx = nullptr;
    }
    QMutexLocker locker(&m_mutex);
    m_fullAudioData.clear();
    m_peakPyramid.clear();
}

void AudioDecoder::setSampleRate(int sampleRate) {
    if (m_sampleRate == sampleRate) {
        return;
    }
    m_sampleRate = sampleRate;
    scheduleStart(); // サンプルレート変更時は再デコード
}

void AudioDecoder::seek(qint64 ms) { emit seekRequested(ms); }

auto AudioDecoder::getSamples(double startTime, int count) -> std::vector<float> { // NOLINT(bugprone-easily-swappable-parameters)
    QMutexLocker locker(&m_mutex);

    // startTimeが負数の場合のアンダーフローを防ぐ（size_tへのキャスト前にクランプ）
    startTime = std::max(startTime, 0.0);

    // startTime (秒) × m_sampleRate (サンプル/秒) × 2 (ステレオ 2ch)
    auto startIdx = static_cast<size_t>(startTime * m_sampleRate * 2);

    // 偶数アライメント（L/R がずれないように補正）
    if (startIdx % 2 != 0 && startIdx > 0) {
        startIdx--;
    }

    if (startIdx >= m_fullAudioData.size()) {
        return std::vector<float>(count, 0.0F);
    }

    size_t available = m_fullAudioData.size() - startIdx;
    size_t actualCount = std::min(static_cast<size_t>(count), available);

    std::vector<float> result(m_fullAudioData.begin() + static_cast<ptrdiff_t>(startIdx), m_fullAudioData.begin() + static_cast<ptrdiff_t>(startIdx + actualCount));

    // 足りない分は無音で埋める
    if (result.size() < static_cast<size_t>(count)) {
        result.resize(count, 0.0F);
    }

    return result;
}

void AudioDecoder::buildPeakCache() {
    QMutexLocker locker(&m_mutex);
    m_peakPyramid.clear();
    if (m_fullAudioData.empty()) {
        return;
    }

    int numSamples = static_cast<int>(m_fullAudioData.size() / 2);

    // Level 0: 32サンプルごとの最小・最大値 (高精度)
    PeakLevel base;
    base.samplesPerEntry = 32;
    base.peaks.reserve((numSamples / 32) + 1);

    for (int i = 0; i < numSamples; i += 32) {
        float pMin = 0.0F;
        float pMax = 0.0F;
        for (int j = 0; j < 32 && (i + j) < numSamples; ++j) {
            float l = m_fullAudioData[static_cast<std::size_t>(i + j) * 2];
            float r = m_fullAudioData[(static_cast<std::size_t>(i + j) * 2) + 1];
            pMin = std::min({pMin, l, r});
            pMax = std::max({pMax, l, r});
        }
        base.peaks.push_back({.min = pMin, .max = pMax});
    }
    m_peakPyramid.push_back(std::move(base));

    // Level 1-5: 前のレベルの8要素(8倍速)から最大・最小を抽出
    for (int i = 0; i < 5; ++i) {
        const auto &prev = m_peakPyramid.back();
        if (prev.peaks.size() < 8) {
            break;
        }

        PeakLevel next;
        next.samplesPerEntry = prev.samplesPerEntry * 8;
        next.peaks.reserve((prev.peaks.size() / 8) + 1);

        for (size_t j = 0; j < prev.peaks.size(); j += 8) {
            float pMin = 0.0F;
            float pMax = 0.0F;
            for (size_t k = 0; k < 8 && (j + k) < prev.peaks.size(); ++k) {
                pMin = std::min(pMin, prev.peaks[j + k].min);
                pMax = std::max(pMax, prev.peaks[j + k].max);
            }
            next.peaks.push_back({.min = pMin, .max = pMax});
        }
        m_peakPyramid.push_back(std::move(next));
    }
}

auto AudioDecoder::getPeaks(double startSec, double durationSec, int pixelWidth) -> std::vector<float> {
    QMutexLocker locker(&m_mutex);
    if (pixelWidth <= 0) {
        return {};
    }
    if (m_fullAudioData.empty()) {
        return std::vector<float>(static_cast<std::size_t>(pixelWidth) * 2, 0.0F);
    }

    double totalSamplesInView = durationSec * m_sampleRate;
    double samplesPerPixel = totalSamplesInView / pixelWidth;

    std::vector<float> result;
    result.reserve(static_cast<std::size_t>(pixelWidth) * 2);

    if (samplesPerPixel < 32.0) {
        // 超高精度: キャッシュレベルを超えたズーム時は生データを直接スキャン
        int numSamples = static_cast<int>(m_fullAudioData.size() / 2);
        for (int i = 0; i < pixelWidth; ++i) {
            int idxStart = std::clamp(static_cast<int>((startSec + (durationSec * i / pixelWidth)) * m_sampleRate), 0, numSamples - 1);
            int idxEnd = std::clamp(static_cast<int>((startSec + (durationSec * (i + 1) / pixelWidth)) * m_sampleRate), idxStart + 1, numSamples);
            float pMin = 0.0F;
            float pMax = 0.0F;
            for (int j = idxStart; j < idxEnd; ++j) {
                pMin = std::min({pMin, m_fullAudioData[static_cast<std::size_t>(j) * 2], m_fullAudioData[(static_cast<std::size_t>(j) * 2) + 1]});
                pMax = std::max({pMax, m_fullAudioData[static_cast<std::size_t>(j) * 2], m_fullAudioData[(static_cast<std::size_t>(j) * 2) + 1]});
            }
            result.push_back(pMin);
            result.push_back(pMax);
        }
    } else {
        // 通常・広域表示: ピラミッドキャッシュを使用
        size_t levelIdx = 0;
        for (size_t i = 0; i < m_peakPyramid.size(); ++i) {
            if (m_peakPyramid[i].samplesPerEntry <= samplesPerPixel) {
                levelIdx = i;
            } else {
                break;
            }
        }
        const auto &level = m_peakPyramid[levelIdx];
        for (int i = 0; i < pixelWidth; ++i) {
            auto entryIdx = static_cast<size_t>(((startSec + (durationSec * i / pixelWidth)) * m_sampleRate) / level.samplesPerEntry);
            if (entryIdx < level.peaks.size()) {
                result.push_back(level.peaks[entryIdx].min);
                result.push_back(level.peaks[entryIdx].max);
            } else {
                result.push_back(0.0F);
                result.push_back(0.0F);
            }
        }
    }
    return result;
}

auto AudioDecoder::totalDurationSec() const -> double {
    QMutexLocker locker(&m_mutex);
    if (m_sampleRate <= 0) {
        return 0.0;
    }
    const double frames = static_cast<double>(m_fullAudioData.size()) / 2.0;
    return frames / static_cast<double>(m_sampleRate);
}

void AudioDecoder::setPlaying(bool playing) {
    // 再生状態をスレッドセーフに更新
    m_isPlaying.store(playing, std::memory_order_release);
}

} // namespace AviQtl::Core

#include "compute_effect.hpp"
#include "compute_render_node.hpp"
#include <QDebug>
#include <QSGNode>
#include <algorithm>
#include <cmath>
#include <cstring>

namespace AviQtl::UI::Effects {

ComputeEffect::ComputeEffect(QQuickItem *parent) : QQuickItem(parent) { setFlag(ItemHasContents, true); }

ComputeEffect::~ComputeEffect() = default;

void ComputeEffect::setParams(const QVariantMap &params) {
    if (m_params == params)
        return;
    m_params = params;
    m_dirty = true;
    emit paramsChanged();
    update();
}

void ComputeEffect::setStorageBuffers(const QVariantMap &buffers) {
    if (m_storageBuffers == buffers)
        return;
    m_storageBuffers = buffers;
    m_dirty = true;
    emit storageBuffersChanged();
    update();
}

void ComputeEffect::setEnabled(bool enabled) {
    if (m_enabled == enabled)
        return;
    m_enabled = enabled;
    m_dirty = true;
    emit enabledChanged();
    update();
}

void ComputeEffect::setShaderPath(const QString &path) {
    if (m_shaderPath == path)
        return;
    m_shaderPath = path;
    m_dirty = true;
    emit shaderPathChanged();
    update();
}

// フェーズ8: ワークグループサイズのセッタ
void ComputeEffect::setWorkGroupSizeX(int x) {
    const int clamped = qMax(1, x);
    if (m_workGroupX == clamped)
        return;
    m_workGroupX = clamped;
    m_dirty = true;
    emit workGroupSizeXChanged();
    update();
}

void ComputeEffect::setWorkGroupSizeY(int y) {
    const int clamped = qMax(1, y);
    if (m_workGroupY == clamped)
        return;
    m_workGroupY = clamped;
    m_dirty = true;
    emit workGroupSizeYChanged();
    update();
}

void ComputeEffect::setAutoWorkGroup(bool autoWG) {
    if (m_autoWorkGroup == autoWG)
        return;
    m_autoWorkGroup = autoWG;
    if (m_autoWorkGroup)
        recalcAutoWorkGroup();
    m_dirty = true;
    emit autoWorkGroupChanged();
    update();
}

// フェーズ6 / 8: ECS writeSSBOLayout → GPU への直接ゼロコピーパス
// フェーズ8: このデータは updatePaintNode で ComputeRenderNode に同期される
void ComputeEffect::setStorageBufferRaw(const QString &name, int binding, const void *data, qsizetype byteSize) {
    for (auto &entry : m_rawSSBOs) {
        if (entry.name == name) {
            if (entry.data.size() == byteSize && std::memcmp(entry.data.constData(), data, static_cast<std::size_t>(byteSize)) == 0)
                return;
            entry.binding = binding;
            entry.data = QByteArray(static_cast<const char *>(data), static_cast<qsizetype>(byteSize));
            m_dirty = true;
            update();
            return;
        }
    }
    m_rawSSBOs.push_back(RawSSBOEntry{name, binding, QByteArray(static_cast<const char *>(data), static_cast<qsizetype>(byteSize))});
    m_dirty = true;
    update();
}

// フェーズ8: アイテムリサイズ時に autoWorkGroup が true なら自動再計算
void ComputeEffect::geometryChange(const QRectF &newGeometry, const QRectF &oldGeometry) {
    QQuickItem::geometryChange(newGeometry, oldGeometry);
    if (m_autoWorkGroup)
        recalcAutoWorkGroup();
}

// 16x16 スレッドを 1 ワークグループとして item の縦横スレッド数を算出する
// アイテム幅/高さが 0 の場合はデフォルト (1x1) を維持する
void ComputeEffect::recalcAutoWorkGroup() {
    if (width() > 0.0) {
        const int newX = qMax(1, static_cast<int>(std::ceil(width() / 16.0)));
        if (m_workGroupX != newX) {
            m_workGroupX = newX;
            emit workGroupSizeXChanged();
        }
    }
    if (height() > 0.0) {
        const int newY = qMax(1, static_cast<int>(std::ceil(height() / 16.0)));
        if (m_workGroupY != newY) {
            m_workGroupY = newY;
            emit workGroupSizeYChanged();
        }
    }
}

// QVariantMap → バイト列変換 (旧来の互換パス。フェーズ6以降は setStorageBufferRaw を優先)
auto ComputeEffect::ssboToBytes(const QVariantMap &bufferData) -> QByteArray {
    QByteArray result;
    result.reserve(static_cast<qsizetype>(bufferData.size()) * static_cast<qsizetype>(sizeof(float)));
    for (const QVariant &v : bufferData.values()) {
        if (v.canConvert<float>()) {
            float f = v.toFloat();
            result.append(reinterpret_cast<const char *>(&f), sizeof(float));
        } else if (v.canConvert<int>()) {
            int i = v.toInt();
            result.append(reinterpret_cast<const char *>(&i), sizeof(int));
        }
    }
    return result;
}

void ComputeEffect::updateState() {
    // フェーズ8: m_rawSSBOs の内容は updatePaintNode → ComputeRenderNode::syncSSBOs で転送済み
}

// フェーズ8: ComputeRenderNode を生成・更新して返す
// updatePaintNode は UI/レンダースレッドの同期ポイントであるため
// m_rawSSBOs へのアクセスに mutex は不要
auto ComputeEffect::updatePaintNode(QSGNode *oldNode, UpdatePaintNodeData *) -> QSGNode * {
    if (!m_enabled) {
        delete oldNode;
        return nullptr;
    }

    // フェーズ8: 初回呼び出し時に ComputeRenderNode を生成する
    auto *node = static_cast<ComputeRenderNode *>(oldNode);
    if (!node) {
        node = new ComputeRenderNode(window());
        m_dirty = true;
    }

    if (m_dirty) {
        // m_rawSSBOs → ComputeRenderNode::SSBOEntry に変換して転送
        QList<ComputeRenderNode::SSBOEntry> entries;
        if (!m_rawSSBOs.isEmpty()) {
            entries.reserve(m_rawSSBOs.size());
            for (const auto &raw : std::as_const(m_rawSSBOs))
                entries.push_back({raw.binding, raw.data});
        } else if (!m_storageBuffers.isEmpty()) {
            // 旧来 QVariantMap パス: m_rawSSBOs が空の場合のみ使用する
            for (auto it = m_storageBuffers.cbegin(); it != m_storageBuffers.cend(); ++it) {
                const QByteArray bytes = ssboToBytes(it.value().toMap());
                if (!bytes.isEmpty())
                    entries.push_back({0, bytes});
            }
        }

        node->syncSSBOs(entries);
        node->syncShaderPath(m_shaderPath);
        node->syncWorkGroupSize(m_workGroupX, m_workGroupY);
        m_dirty = false;
    }

    // QSGNode のダーティフラグを立てて prepare() / render() が呼ばれることを保証する
    node->markDirty(QSGNode::DirtyMaterial);
    return node;
}

} // namespace AviQtl::UI::Effects

#include "compute_render_node.hpp"
#include <QFile>
#include <QLoggingCategory>
#include <QQuickWindow>
#include <QSGRendererInterface>
#include <rhi/qrhi.h>

Q_LOGGING_CATEGORY(lcComputeRenderNode, "aviqtl.compute_render_node")

namespace AviQtl::UI::Effects {

ComputeRenderNode::ComputeRenderNode(QQuickWindow *window) : m_window(window) {}

ComputeRenderNode::~ComputeRenderNode() { destroyResources(); }

void ComputeRenderNode::syncSSBOs(const QList<SSBOEntry> &entries) {
    // バッファの binding セットが変わった場合はレイアウト再構築フラグを立てる
    bool layoutChanged = (m_gpuBuffers.size() != entries.size());
    if (!layoutChanged) {
        for (int i = 0; i < entries.size(); ++i) {
            if (m_gpuBuffers[i].binding != entries[i].binding) {
                layoutChanged = true;
                break;
            }
        }
    }
    m_pendingSSBOs = entries;
    m_ssboDirty = !entries.isEmpty();
    if (layoutChanged)
        m_bufferLayoutDirty = true;
}

void ComputeRenderNode::syncShaderPath(const QString &path) {
    if (m_shaderPath == path)
        return;
    m_shaderPath = path;
    m_shaderDirty = true;
}

void ComputeRenderNode::syncWorkGroupSize(int x, int y, int z) {
    m_workGroupX = qMax(1, x);
    m_workGroupY = qMax(1, y);
    m_workGroupZ = qMax(1, z);
}

QRhi *ComputeRenderNode::resolveRhi() const { return static_cast<QRhi *>(m_window->rendererInterface()->getResource(m_window, QSGRendererInterface::RhiResource)); }

QRhiCommandBuffer *ComputeRenderNode::resolveCommandBuffer() const {
    auto *ri = m_window->rendererInterface();
    // Qt 6.6+: RhiRedirectCommandBuffer がメインレンダーパス前のコマンドバッファ
    // それ以前: CommandListResource にフォールバック
    auto *cb = static_cast<QRhiCommandBuffer *>(ri->getResource(m_window, QSGRendererInterface::RhiRedirectCommandBuffer));
    if (!cb) {
        cb = static_cast<QRhiCommandBuffer *>(ri->getResource(m_window, QSGRendererInterface::CommandListResource));
    }
    return cb;
}

bool ComputeRenderNode::ensureBuffers(QRhi *rhi) {
    if (!m_bufferLayoutDirty)
        return !m_gpuBuffers.isEmpty();

    // 既存 GPU バッファと SRB を破棄
    for (auto &gb : m_gpuBuffers) {
        delete gb.buf;
        gb.buf = nullptr;
    }
    m_gpuBuffers.clear();
    delete m_srb;
    m_srb = nullptr;

    if (m_pendingSSBOs.isEmpty()) {
        m_bufferLayoutDirty = false;
        return false;
    }

    // 各 SSBO エントリに対応する Dynamic StorageBuffer を確保
    for (const auto &entry : std::as_const(m_pendingSSBOs)) {
        const qsizetype sz = entry.data.size();
        if (sz == 0)
            continue;
        auto *buf = rhi->newBuffer(QRhiBuffer::Dynamic, QRhiBuffer::StorageBuffer, static_cast<quint32>(sz));
        if (!buf->create()) {
            qCWarning(lcComputeRenderNode) << "QRhiBuffer::create() 失敗 binding=" << entry.binding;
            delete buf;
            return false;
        }
        m_gpuBuffers.push_back({entry.binding, buf, sz});
    }

    // SRB 構築: GpuClipSoA は Compute Shader からの読み取り専用なので bufferLoad を使用
    m_srb = rhi->newShaderResourceBindings();
    QList<QRhiShaderResourceBinding> bindings;
    bindings.reserve(m_gpuBuffers.size());
    for (const auto &gb : std::as_const(m_gpuBuffers)) {
        bindings.append(QRhiShaderResourceBinding::bufferLoad(gb.binding, QRhiShaderResourceBinding::ComputeStage, gb.buf));
    }
    m_srb->setBindings(bindings.cbegin(), bindings.cend());
    if (!m_srb->create()) {
        qCWarning(lcComputeRenderNode) << "QRhiShaderResourceBindings::create() 失敗";
        return false;
    }

    m_bufferLayoutDirty = false;
    // バッファレイアウト変更 → パイプラインも SRB を参照しているため再構築が必要
    m_shaderDirty = true;
    return true;
}

bool ComputeRenderNode::ensurePipeline(QRhi *rhi) {
    if (!m_shaderDirty)
        return m_pipeline != nullptr;

    delete m_pipeline;
    m_pipeline = nullptr;

    if (m_shaderPath.isEmpty()) {
        qCDebug(lcComputeRenderNode) << "shaderPath 未設定 (パイプライン構築スキップ)";
        return false;
    }
    if (!m_srb) {
        qCWarning(lcComputeRenderNode) << "SRB が未構築: ensureBuffers() を先に呼ぶこと";
        return false;
    }

    // .qsb ファイルをロード (Qt Shader Baker 出力形式)
    QFile f(m_shaderPath);
    if (!f.open(QIODevice::ReadOnly)) {
        qCWarning(lcComputeRenderNode) << "シェーダーファイルが開けません:" << m_shaderPath;
        return false;
    }
    m_shader = QShader::fromSerialized(f.readAll());
    if (!m_shader.isValid()) {
        qCWarning(lcComputeRenderNode) << "無効な .qsb ファイル:" << m_shaderPath;
        return false;
    }

    m_pipeline = rhi->newComputePipeline();
    m_pipeline->setShaderStage({QRhiShaderStage::Compute, m_shader});
    m_pipeline->setShaderResourceBindings(m_srb);
    if (!m_pipeline->create()) {
        qCWarning(lcComputeRenderNode) << "QRhiComputePipeline::create() 失敗";
        delete m_pipeline;
        m_pipeline = nullptr;
        return false;
    }

    m_shaderDirty = false;
    qCDebug(lcComputeRenderNode) << "パイプライン構築完了:" << m_shaderPath;
    return true;
}

void ComputeRenderNode::prepare() {
    m_rhi = resolveRhi();
    if (!m_rhi)
        return;

    // バッファ確保 → SRB 構築
    if (!ensureBuffers(m_rhi))
        return;

    // パイプライン構築 (シェーダーロード + QRhiComputePipeline::create())
    if (!ensurePipeline(m_rhi))
        return;

    if (!m_ssboDirty)
        return;

    auto *cb = resolveCommandBuffer();
    if (!cb)
        return;

    // CPU → GPU アップロードバッチを構築
    QRhiResourceUpdateBatch *batch = m_rhi->nextResourceUpdateBatch();
    for (const auto &entry : std::as_const(m_pendingSSBOs)) {
        for (const auto &gb : std::as_const(m_gpuBuffers)) {
            if (gb.binding != entry.binding || !gb.buf)
                continue;
            // Dynamic バッファの部分更新: サイズ不一致は ensureBuffers 内の再確保で吸収済み
            const quint32 uploadSize = static_cast<quint32>(qMin(entry.data.size(), gb.size));
            batch->updateDynamicBuffer(gb.buf, 0, uploadSize, entry.data.constData());
            break;
        }
    }

    // Compute パスを実行 (batch は beginComputePass で消費される)
    cb->beginComputePass(batch);
    cb->setComputePipeline(m_pipeline);
    cb->setShaderResources(m_srb);
    cb->dispatch(m_workGroupX, m_workGroupY, m_workGroupZ);
    cb->endComputePass();

    m_ssboDirty = false;
}

void ComputeRenderNode::render(const RenderState *) {
    // フェーズ8: 実 GPU 処理は prepare() の Compute Dispatch で完結
    // フェーズ9 でここに SceneGraph Compositor の出力テクスチャブリットを追加する
}

void ComputeRenderNode::releaseResources() { destroyResources(); }

void ComputeRenderNode::destroyResources() {
    delete m_pipeline;
    m_pipeline = nullptr;
    delete m_srb;
    m_srb = nullptr;
    for (auto &gb : m_gpuBuffers) {
        delete gb.buf;
        gb.buf = nullptr;
    }
    m_gpuBuffers.clear();
    m_bufferLayoutDirty = true;
    m_shaderDirty = true;
}

QSGRenderNode::StateFlags ComputeRenderNode::changedStates() const {
    // Compute パスはグラフィクスレンダーステートを変更しない
    return {};
}

QSGRenderNode::RenderingFlags ComputeRenderNode::flags() const {
    // BoundedRectRendering: バウンディングボックス内のみ描画
    // OpaqueRendering: アルファブレンド不要
    return BoundedRectRendering | OpaqueRendering;
}

