Window {
    id: root

    property var project: Workspace.currentTimeline ? Workspace.currentTimeline.project : null
    readonly property double pFps: project ? project.fps : 60
    property string defaultCodec: SettingsManager ? SettingsManager.value("exportDefaultCodec", "h264_vaapi") : "h264_vaapi"
    property int defaultBitrateMbps: SettingsManager ? SettingsManager.value("exportDefaultBitrateMbps", 15) : 15
    property int defaultCrf: SettingsManager ? SettingsManager.value("exportDefaultCrf", 20) : 20
    property string defaultAudioCodec: SettingsManager ? SettingsManager.value("exportDefaultAudioCodec", "aac") : "aac"
    property int defaultAudioKbps: SettingsManager ? SettingsManager.value("exportDefaultAudioBitrateKbps", 192) : 192

    function show() {
        visible = true;
    }

    function open() {
        visible = true;
    }

    title: qsTr("メディアの書き出し")
    width: 620
    height: 580
    modality: Qt.ApplicationModal
    flags: Qt.Dialog | Qt.WindowCloseButtonHint

    // 進捗オーバーレイ
    Rectangle {
        id: progressOverlay

        anchors.fill: parent
        color: Qt.rgba(0, 0, 0, 0.75)
        visible: Workspace.currentTimeline && Workspace.currentTimeline.isExporting
        z: 100

        ColumnLayout {
            anchors.centerIn: parent
            spacing: 16
            width: parent.width * 0.7

            Label {
                Layout.alignment: Qt.AlignHCenter
                text: qsTr("書き出し中...")
                font.pixelSize: 16
                font.bold: true
                color: "white"
            }

            ProgressBar {
                id: exportProgressBar

                Layout.fillWidth: true
                from: 0
                to: 100
                value: 0
            }

            Label {
                id: progressLabel

                Layout.alignment: Qt.AlignHCenter
                text: qsTr("0 / 0 フレーム")
                color: palette.mid
                font.pixelSize: 11
            }

            Button {
                Layout.alignment: Qt.AlignHCenter
                text: qsTr("キャンセル")
                onClicked: Workspace.currentTimeline.cancelExport()
            }

        }

    }

    // 進捗シグナルの受信
    Connections {
        function onExportProgressChanged(progress, current, total) {
            exportProgressBar.value = progress;
            progressLabel.text = qsTr("%1 / %2 フレーム").arg(current).arg(total);
        }

        function onExportFinished(success, message) {
            resultPopup.message = message;
            resultPopup.success = success;
            resultPopup.open();
        }

        target: Workspace.currentTimeline
    }

    // 完了ポップアップ
    Dialog {
        id: resultPopup

        property string message: ""
        property bool success: true

        title: success ? qsTr("完了") : qsTr("エラー")
        modal: true
        anchors.centerIn: parent
        standardButtons: Dialog.Ok

        Label {
            text: resultPopup.message
        }

    }

    // メインUI
    ColumnLayout {
        anchors.fill: parent
        anchors.margins: 16
        spacing: 12

        // ファイルパス
        RowLayout {
            Layout.fillWidth: true

            TextField {
                id: filePathField

                Layout.fillWidth: true
                placeholderText: qsTr("保存先ファイルパス...")
            }

            Button {
                text: qsTr("参照...")
                onClicked: fileDialog.open()
            }

        }

        // ビデオ設定
        GroupBox {
            title: qsTr("映像")
            Layout.fillWidth: true

            GridLayout {
                columns: 4
                rowSpacing: 8
                columnSpacing: 12
                width: parent.width

                Label {
                    text: qsTr("解像度:")
                }

                Label {
                    text: ((project ? project.width : 1920)) + " × " + ((project ? project.height : 1080))
                    font.bold: true
                    Layout.columnSpan: 3
                }

                Label {
                    text: qsTr("FPS:")
                }

                Label {
                    text: pFps.toFixed(3)
                    font.bold: true
                    Layout.columnSpan: 3
                }

                Label {
                    text: qsTr("コーデック:")
                }

                ComboBox {
                    id: codecCombo

                    Layout.columnSpan: 3
                    Layout.fillWidth: true
                    model: [{
                        "text": "H.264 – libx264 (SW)",
                        "value": "libx264"
                    }, {
                        "text": "H.264 – NVENC (NVIDIA)",
                        "value": "h264_nvenc"
                    }, {
                        "text": "H.264 – AMF (AMD)",
                        "value": "h264_amf"
                    }, {
                        "text": "H.264 – QSV (Intel)",
                        "value": "h264_qsv"
                    }, {
                        "text": "H.264 – VAAPI (Linux)",
                        "value": "h264_vaapi"
                    }, {
                        "text": "HEVC – libx265 (SW)",
                        "value": "libx265"
                    }, {
                        "text": "HEVC – NVENC (NVIDIA)",
                        "value": "hevc_nvenc"
                    }, {
                        "text": "HEVC – AMF (AMD)",
                        "value": "hevc_amf"
                    }, {
                        "text": "HEVC – QSV (Intel)",
                        "value": "hevc_qsv"
                    }, {
                        "text": "HEVC – VAAPI (Linux)",
                        "value": "hevc_vaapi"
                    }, {
                        "text": "AV1 – libaom (SW)",
                        "value": "libaom-av1"
                    }, {
                        "text": "AV1 – NVENC (NVIDIA)",
                        "value": "av1_nvenc"
                    }, {
                        "text": "AV1 – AMF (AMD)",
                        "value": "av1_amf"
                    }, {
                        "text": "AV1 – VAAPI (Linux)",
                        "value": "av1_vaapi"
                    }]
                    textRole: "text"
                    Component.onCompleted: {
                        var idx = -1;
                        for (var i = 0; i < model.length; i++) {
                            if (model[i].value === root.defaultCodec) {
                                idx = i;
                                break;
                            }
                        }
                        if (idx >= 0)
                            currentIndex = idx;
                        else
                            currentIndex = 4;
                    }
                }

                Label {
                    text: qsTr("品質モード:")
                }

                ButtonGroup {
                    id: qualityModeGroup
                }

                RadioButton {
                    id: crfRadio

                    text: qsTr("CRF")
                    ButtonGroup.group: qualityModeGroup
                    checked: true
                }

                RadioButton {
                    text: qsTr("ビットレート")
                    ButtonGroup.group: qualityModeGroup
                }

                Item {
                    Layout.columnSpan: 1
                }

                // CRF スライダー
                Label {
                    text: qsTr("CRF:")
                    visible: crfRadio.checked
                }

                RowLayout {
                    visible: crfRadio.checked
                    Layout.columnSpan: 3
                    Layout.fillWidth: true

                    Slider {
                        id: crfSlider

                        Layout.fillWidth: true
                        from: 0
                        to: 51
                        value: root.defaultCrf
                        stepSize: 1
                    }

                    Label {
                        text: crfSlider.value.toFixed(0)
                        Layout.preferredWidth: 28
                    }

                    Label {
                        text: crfSlider.value <= 17 ? qsTr("高品質") : crfSlider.value <= 28 ? qsTr("標準") : qsTr("低品質")
                        font.pixelSize: 10
                        color: crfSlider.value <= 17 ? "#44cc88" : crfSlider.value <= 28 ? palette.text : "#cc4444"
                    }

                }

                // ビットレート入力
                Label {
                    text: qsTr("ビットレート:")
                    visible: !crfRadio.checked
                }

                RowLayout {
                    visible: !crfRadio.checked
                    Layout.columnSpan: 3

                    SpinBox {
                        id: bitrateSpin

                        from: 1
                        to: 500
                        value: root.defaultBitrateMbps
                        stepSize: 1
                        editable: true
                        textFromValue: (v) => {
                            return qsTr("%1 Mbps").arg(v);
                        }
                        valueFromText: (t) => {
                            return parseInt(t);
                        }
                    }

                }

            }

        }

        // オーディオ設定
        GroupBox {
            title: qsTr("音声")
            Layout.fillWidth: true

            GridLayout {
                columns: 4
                rowSpacing: 8
                columnSpacing: 12
                width: parent.width

                Label {
                    text: qsTr("コーデック:")
                }

                ComboBox {
                    id: audioCodecCombo

                    Layout.columnSpan: 3
                    Layout.fillWidth: true
                    model: [{
                        "text": "AAC",
                        "value": "aac"
                    }, {
                        "text": "Opus",
                        "value": "libopus"
                    }, {
                        "text": "MP3",
                        "value": "libmp3lame"
                    }, {
                        "text": "FLAC (可逆)",
                        "value": "flac"
                    }, {
                        "text": "PCM 16-bit",
                        "value": "pcm_s16le"
                    }]
                    textRole: "text"
                    Component.onCompleted: {
                        var idx = -1;
                        for (var i = 0; i < model.length; i++) {
                            if (model[i].value === root.defaultAudioCodec) {
                                idx = i;
                                break;
                            }
                        }
                        if (idx >= 0)
                            currentIndex = idx;
                        else
                            currentIndex = 0;
                    }
                }

                Label {
                    text: qsTr("ビットレート:")
                }

                ComboBox {
                    id: audioBitrateCombo

                    property int bitrate: [96000, 128000, 192000, 256000, 320000][currentIndex]

                    Layout.columnSpan: 3
                    enabled: audioCodecCombo.currentIndex < 3 // PCM/FLACは無効
                    model: ["96 kbps", "128 kbps", "192 kbps", "256 kbps", "320 kbps"]
                    Component.onCompleted: {
                        var bitrateList = [96, 128, 192, 256, 320];
                        var idx = bitrateList.indexOf(root.defaultAudioKbps);
                        if (idx >= 0)
                            currentIndex = idx;
                        else
                            currentIndex = 2;
                    }
                }

            }

        }

        // 範囲設定
        GroupBox {
            title: qsTr("範囲")
            Layout.fillWidth: true

            RowLayout {
                width: parent.width
                spacing: 12

                CheckBox {
                    id: fullRangeCheck

                    text: qsTr("タイムライン全体")
                    checked: true
                }

                Label {
                    text: qsTr("開始:")
                }

                SpinBox {
                    id: startFrameSpin

                    enabled: !fullRangeCheck.checked
                    from: 0
                    to: endFrameSpin.value - 1
                    value: 0
                    editable: true
                }

                Label {
                    text: qsTr("終了:")
                }

                SpinBox {
                    id: endFrameSpin

                    enabled: !fullRangeCheck.checked
                    from: startFrameSpin.value + 1
                    to: 99999
                    value: 300
                    editable: true
                    Component.onCompleted: {
                        if (Workspace.currentTimeline && Workspace.currentTimeline.timelineDuration > 0)
                            value = Workspace.currentTimeline.timelineDuration;

                    }

                    Connections {
                        function onClipsChanged() {
                            if (Workspace.currentTimeline && Workspace.currentTimeline.timelineDuration > 0)
                                endFrameSpin.value = Workspace.currentTimeline.timelineDuration;

                        }

                        target: Workspace.currentTimeline
                    }

                }

                Label {
                    text: {
                        var s = fullRangeCheck.checked ? 0 : startFrameSpin.value;
                        var e = fullRangeCheck.checked ? (Workspace.currentTimeline ? Workspace.currentTimeline.timelineDuration : 300) : endFrameSpin.value;
                        var sec = (e - s) / pFps;
                        return qsTr("(%1 フレーム / %2 秒)").arg(e - s).arg(sec.toFixed(2));
                    }
                    font.pixelSize: 11
                    color: palette.mid
                }

            }

        }

        Item {
            Layout.fillHeight: true
        }

        // ボタン
        RowLayout {
            Layout.fillWidth: true

            Item {
                Layout.fillWidth: true
            }

            Button {
                text: qsTr("キャンセル")
                onClicked: root.close()
            }

            Button {
                text: qsTr("書き出し開始")
                enabled: filePathField.text !== ""
                highlighted: true
                onClicked: {
                    var codec = codecCombo.model[codecCombo.currentIndex].value;
                    var audioCodec = audioCodecCombo.model[audioCodecCombo.currentIndex].value;
                    Workspace.currentTimeline.exportVideoAsync({
                        "width": (project ? project.width : 1920),
                        "height": (project ? project.height : 1080),
                        "fps_num": Math.round(pFps * 1000),
                        "fps_den": 1000,
                        "bitrate": bitrateSpin.value * 1e+06,
                        "crf": crfRadio.checked ? crfSlider.value : -1,
                        "codecName": codec,
                        "audioCodecName": audioCodec,
                        "audioBitrate": audioBitrateCombo.bitrate,
                        "outputUrl": filePathField.text,
                        "startFrame": fullRangeCheck.checked ? 0 : startFrameSpin.value,
                        "endFrame": fullRangeCheck.checked ? -1 : endFrameSpin.value
                    });
                }
            }

        }

    }

    Dialogs.FileDialog {
        id: fileDialog

        title: qsTr("保存先を指定")
        fileMode: Dialogs.FileDialog.SaveFile
        nameFilters: ["MP4 Video (*.mp4)", "MKV Video (*.mkv)", "All files (*)"]
        onAccepted: {
            var path = selectedFile.toString();
            filePathField.text = Qt.platform.os === "windows" ? path.replace(/^file:\/{3}/, "") : path.replace(/^file:\/\//, "");
        }
    }

}

import Qt.labs.platform as Platform
import QtQuick
import QtQuick.Controls
import QtQuick.Layouts
import QtQuick.Window
import "common" as Common

ApplicationWindow {
    // Global Shortcuts

    id: mainWin

    // 全タブ横断で未保存確認し、全て処理済みになってから finalAction を実行
    function checkAllUnsavedAndExecute(finalAction) {
        if (!Workspace || !Workspace.tabs) {
            finalAction();
            return ;
        }
        for (var i = 0; i < Workspace.tabs.length; i++) {
            if (Workspace.tabs[i].hasUnsavedChanges) {
                // 対象タブをアクティブにしてダイアログを出す
                Workspace.currentIndex = i;
                saveConfirmDialog.pendingAction = function() {
                    // 保存/破棄が完了したら次の未保存タブへ進む
                    checkAllUnsavedAndExecute(finalAction);
                };
                saveConfirmDialog.open();
                return ; // ダイアログ完了を待つ（Cancelは pendingAction=null で自然停止）
            }
        }
        // 未保存タブが 0 なら即実行
        finalAction();
    }

    // 単一タブを対象にした確認（tabIndex が指定されたらそのタブをアクティブにする）
    function checkSaveAndExecute(action, tabIndex) {
        if (tabIndex !== undefined && Workspace.currentIndex !== tabIndex)
            Workspace.currentIndex = tabIndex;

        if (Workspace.currentTimeline && Workspace.currentTimeline.hasUnsavedChanges) {
            saveConfirmDialog.pendingAction = action;
            saveConfirmDialog.open();
        } else {
            action();
        }
    }

    // 修正: 有効なプロジェクト（タブ）が存在しない場合はメインウィンドウを非表示にする。
    // これにより、不必要なレンダリングコンテキストの生成とそれによるクラッシュを抑制する。
    visible: Workspace && Workspace.tabs ? Workspace.tabs.length > 0 : false
    width: 640
    height: 360
    x: 100
    y: 100
    title: qsTr("AviQtl - プレビュー")
    onClosing: (close) => {
        // 一旦クローズをキャンセルし、全タブの未保存確認を行ってから終了する
        close.accepted = false;
        checkAllUnsavedAndExecute(function() {
            if (WindowManager)
                WindowManager.requestQuit();

        });
    }
    // 起動時に自分自身(Window)をコントローラーに渡す
    Component.onCompleted: {
        if (Workspace.currentTimeline)
            Workspace.currentTimeline.setCompositeView(compositeView);

    }

    // 末尾到達時に一時停止するだけのシンプルなロジック
    Connections {
        function onCurrentFrameChanged() {
            if (Workspace.currentTimeline && Workspace.currentTimeline.transport) {
                if (Workspace.currentTimeline.transport.totalFrames > 0 && Workspace.currentTimeline.transport.currentFrame >= Workspace.currentTimeline.transport.totalFrames)
                    Workspace.currentTimeline.transport.pause();

            }
        }

        target: Workspace.currentTimeline ? Workspace.currentTimeline.transport : null
    }

    FontLoader {
        source: "qrc:/resources/remixicon.ttf"
    }

    // アクション定義 (ショートカット用)
    Action {
        id: newAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("project.new", "Ctrl+N") : "Ctrl+N"

        text: qsTr("新規プロジェクト")
        onTriggered: {
            // ランチャーで幅・高さ・fps を選ばせてから新規タブを作成する
            WindowManager.showLauncher();
        }
    }

    Action {
        id: saveProjectAction // プロジェクトの上書き保存用アクション

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("project.save", "Ctrl+S") : "Ctrl+S"

        text: qsTr("プロジェクトの上書き保存")
        onTriggered: {
            if (Workspace.currentTimeline) {
                // 現在のプロジェクトパスが未設定の場合は名前を付けて保存ダイアログを開く
                if (Workspace.currentTimeline.currentProjectUrl === "")
                    saveDialog.open();
                else
                    Workspace.currentTimeline.saveProject("");
            }
        }
    }

    Action {
        id: loadAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("project.open", "Ctrl+O") : "Ctrl+O"

        text: qsTr("プロジェクトを開く")
        onTriggered: {
            loadDialog.open();
        }
    }

    Action {
        id: saveAsProjectAction // プロジェクトを名前を付けて保存用アクション

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("project.saveAs", "Ctrl+Shift+S") : "Ctrl+Shift+S"

        text: qsTr("プロジェクトを名前を付けて保存...")
        onTriggered: saveDialog.open()
    }

    Action {
        id: quitAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("app.quit", "Ctrl+Q") : "Ctrl+Q"

        text: qsTr("終了")
        onTriggered: {
            checkAllUnsavedAndExecute(function() {
                if (WindowManager)
                    WindowManager.requestQuit();

            });
        }
    }

    Action {
        id: undoAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("edit.undo", "Ctrl+Z") : "Ctrl+Z"

        text: qsTr("元に戻す")
        onTriggered: {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.undo();

        }
    }

    Action {
        id: redoAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("edit.redo", "Ctrl+Shift+Z") : "Ctrl+Shift+Z"

        text: qsTr("やり直す")
        onTriggered: {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.redo();

        }
    }

    Action {
        id: playPauseAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("transport.playPause", "Space") : "Space"

        text: qsTr("再生 / 一時停止")
        onTriggered: {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.togglePlay();

        }
    }

    Action {
        id: splitAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("timeline.split", "S") : "S"

        text: qsTr("クリップを分割")
        onTriggered: {
            if (Workspace.currentTimeline && Workspace.currentTimeline.transport) {
                var f = Workspace.currentTimeline.transport.currentFrame;
                if (Workspace.currentTimeline.selection && Workspace.currentTimeline.selection.selectedClipId >= 0) {
                    Workspace.currentTimeline.splitClip(Workspace.currentTimeline.selection.selectedClipId, f);
                } else {
                    if (Workspace.currentTimeline.selection && Workspace.currentTimeline.selection.selectedClipIds.length > 0) {
                        for (var i = 0; i < Workspace.currentTimeline.selection.selectedClipIds.length; i++) {
                            Workspace.currentTimeline.splitClip(Workspace.currentTimeline.selection.selectedClipIds[i], f);
                        }
                    }
                }
            }
        }
    }

    Action {
        id: deleteAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("edit.delete", "Delete") : "Delete"

        text: qsTr("削除")
        onTriggered: {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.deleteSelectedClips();

        }
    }

    Action {
        id: copyAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("edit.copy", "Ctrl+C") : "Ctrl+C"

        text: qsTr("コピー")
        onTriggered: {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.copySelectedClips();

        }
    }

    Action {
        id: cutAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("edit.cut", "Ctrl+X") : "Ctrl+X"

        text: qsTr("カット")
        onTriggered: {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.cutSelectedClips();

        }
    }

    Action {
        id: pasteAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("edit.paste", "Ctrl+V") : "Ctrl+V"

        text: qsTr("貼り付け")
        onTriggered: {
            if (Workspace.currentTimeline && Workspace.currentTimeline.transport) {
                var f = Workspace.currentTimeline.transport.currentFrame;
                var l = Workspace.currentTimeline.selectedLayer !== undefined ? Workspace.currentTimeline.selectedLayer : 0;
                Workspace.currentTimeline.pasteClip(f, l);
            }
        }
    }

    Action {
        id: duplicateAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("edit.duplicate", "Ctrl+D") : "Ctrl+D"

        text: qsTr("複製")
        onTriggered: {
            if (Workspace.currentTimeline) {
                Workspace.currentTimeline.copySelectedClips();
                var f = Workspace.currentTimeline.transport ? Workspace.currentTimeline.transport.currentFrame : 0;
                var l = Workspace.currentTimeline.selectedLayer !== undefined ? Workspace.currentTimeline.selectedLayer : 0;
                Workspace.currentTimeline.pasteClip(f, l);
            }
        }
    }

    Action {
        id: nextFrameAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("transport.nextFrame", "Right") : "Right"

        text: qsTr("1フレーム進む")
        onTriggered: {
            if (Workspace.currentTimeline && Workspace.currentTimeline.transport)
                Workspace.currentTimeline.transport.currentFrame = Math.min(Workspace.currentTimeline.transport.currentFrame + 1, Workspace.currentTimeline.transport.totalFrames);

        }
    }

    Action {
        id: prevFrameAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("transport.prevFrame", "Left") : "Left"

        text: qsTr("1フレーム戻る")
        onTriggered: {
            if (Workspace.currentTimeline && Workspace.currentTimeline.transport)
                Workspace.currentTimeline.transport.currentFrame = Math.max(Workspace.currentTimeline.transport.currentFrame - 1, 0);

        }
    }

    Action {
        id: jumpStartAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("transport.jumpStart", "Home") : "Home"

        text: qsTr("先頭へ移動")
        onTriggered: {
            if (Workspace.currentTimeline && Workspace.currentTimeline.transport)
                Workspace.currentTimeline.transport.currentFrame = 0;

        }
    }

    Action {
        id: jumpEndAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("transport.jumpEnd", "End") : "End"

        text: qsTr("末尾へ移動")
        onTriggered: {
            if (Workspace.currentTimeline && Workspace.currentTimeline.transport)
                Workspace.currentTimeline.transport.currentFrame = Workspace.currentTimeline.transport.totalFrames;

        }
    }

    Action {
        id: zoomInAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("view.zoomIn", "Ctrl++") : "Ctrl++"

        text: qsTr("ズームイン")
        onTriggered: {
            if (Workspace.currentTimeline) {
                var step = SettingsManager ? SettingsManager.value("timelineZoomStep", 10) : 10;
                var maxZ = SettingsManager ? SettingsManager.value("timelineZoomMax", 400) : 400;
                Workspace.currentTimeline.timelineScale = Math.min(Workspace.currentTimeline.timelineScale + step / 100, maxZ / 100);
            }
        }
    }

    Action {
        id: zoomOutAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("view.zoomOut", "Ctrl+-") : "Ctrl+-"

        text: qsTr("ズームアウト")
        onTriggered: {
            if (Workspace.currentTimeline) {
                var step = SettingsManager ? SettingsManager.value("timelineZoomStep", 10) : 10;
                var minZ = SettingsManager ? SettingsManager.value("timelineZoomMin", 10) : 10;
                Workspace.currentTimeline.timelineScale = Math.max(Workspace.currentTimeline.timelineScale - step / 100, minZ / 100);
            }
        }
    }

    Action {
        id: moveUpAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("timeline.moveUp", "Alt+Up") : "Alt+Up"

        text: qsTr("レイヤーを上へ移動")
        onTriggered: {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.moveSelectedClips(-1, 0);

        }
    }

    Action {
        id: moveDownAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("timeline.moveDown", "Alt+Down") : "Alt+Down"

        text: qsTr("レイヤーを下へ移動")
        onTriggered: {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.moveSelectedClips(1, 0);

        }
    }

    Action {
        id: nudgeLeftAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("timeline.nudgeLeft", "Alt+Left") : "Alt+Left"

        text: qsTr("1フレーム左へ移動")
        onTriggered: {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.moveSelectedClips(0, -1);

        }
    }

    Action {
        id: nudgeRightAction

        property string shortcutText: SettingsManager ? SettingsManager.shortcut("timeline.nudgeRight", "Alt+Right") : "Alt+Right"

        text: qsTr("1フレーム右へ移動")
        onTriggered: {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.moveSelectedClips(0, 1);

        }
    }

    Platform.MessageDialog {
        id: errorDialog

        title: qsTr("エラー")
        buttons: Platform.MessageDialog.Ok
    }

    Dialog {
        id: saveConfirmDialog

        property var pendingAction: null

        title: qsTr("保存の確認")
        x: (mainWin.width - width) / 2
        y: (mainWin.height - height) / 2
        modal: true
        parent: Overlay.overlay
        standardButtons: Dialog.Save | Dialog.Discard | Dialog.Cancel
        onAccepted: {
            var action = pendingAction;
            pendingAction = null; // 先にリセット（再入防止）
            if (Workspace.currentTimeline) {
                if (Workspace.currentTimeline.currentProjectUrl === "") {
                    // 名前を付けて保存 → saveDialog 完了後に action を実行
                    saveDialog._nextAction = action;
                    saveDialog.open();
                } else {
                    Workspace.currentTimeline.saveProject("");
                    if (action)
                        action();

                }
            }
        }
        onDiscarded: {
            var action = pendingAction;
            pendingAction = null;
            if (action)
                action();

        }
        onRejected: {
            pendingAction = null;
        }

        Label {
            text: qsTr("プロジェクトに保存されていない変更があります。\n続行する前に保存しますか？")
            wrapMode: Text.Wrap
        }

    }

    Connections {
        function onErrorOccurred(message) {
            errorDialog.text = message;
            errorDialog.open();
        }

        target: Workspace.currentTimeline
    }

    // FPSと再生速度の同期設定
    Binding {
        target: Workspace.currentTimeline ? Workspace.currentTimeline.transport : null
        property: "fps"
        value: (Workspace.currentTimeline && Workspace.currentTimeline.project) ? Workspace.currentTimeline.project.fps : 60
    }

    Connections {
        function onPlaybackSpeedChanged() {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.syncPlaybackSpeed();

        }

        target: Workspace.currentTimeline ? Workspace.currentTimeline.transport : null
    }

    Connections {
        function onSampleRateChanged() {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.updateAudioSampleRate();

        }

        target: Workspace.currentTimeline ? Workspace.currentTimeline.project : null
    }

    Connections {
        function onCurrentTimelineChanged() {
            syncCompositeView();
        }

        target: Workspace
    }

    Platform.FileDialog {
        id: saveDialog

        property var _nextAction: null

        title: qsTr("名前を付けて保存")
        fileMode: Platform.FileDialog.SaveFile
        nameFilters: ["AviQtl Project files (*.aviqtl)", "JSON files (*.json)"]
        defaultSuffix: "aviqtl"
        onAccepted: {
            if (Workspace.currentTimeline)
                Workspace.currentTimeline.saveProject(file);

            if (_nextAction)
                _nextAction();

            _nextAction = null;
        }
        onRejected: {
            _nextAction = null;
        }
    }

    Platform.FileDialog {
        id: loadDialog

        title: qsTr("プロジェクトを開く")
