            return i;
        }
        return fallback;
    }

    // シグナルを emit するブリッジ関数
    // （CheckBox / TextArea から root.xxx() 形式で呼ばれるため実装が必要）
    function setPluginEnabled(formatName, enabled) {
        pluginEnabledChanged(formatName, enabled);
