import QtQuick
import QtQuick.Controls
import QtQuick.Layouts

Item {
    id: clipDelegate

    property int layerHeight: 30
    property int layerCount: 128
    property int clipResizeHandleWidth: 6
    property Item flickableContentItem: null
    property var snapFrameFunc: function(f, ignoreSnap) {
        return f;
    }
    property int resizeDraftStart: -1
    property int resizeDraftDuration: -1
    property double scale: Workspace.currentTimeline ? Workspace.currentTimeline.timelineScale : 1
    property bool forceVisualSelection: false
    property var forcedSelectedIds: []
    readonly property bool committedSelected: ((Workspace.currentTimeline && Workspace.currentTimeline.selection) ? (Workspace.currentTimeline.selection.selectedClipIds.includes(modelData.id)) : false)
    readonly property bool previewSelected: Workspace.currentTimeline && Workspace.currentTimeline.previewSelectionIds ? Workspace.currentTimeline.previewSelectionIds.includes(modelData.id) : false
    readonly property bool forcedSelected: forceVisualSelection && forcedSelectedIds.includes(modelData.id)
    readonly property bool isSelected: previewSelected || (forceVisualSelection ? forcedSelected : committedSelected)
    readonly property bool isLayerLocked: getLayerLocked(modelData.layer)
    property string clipDisplayName: (typeof modelData.name === "string" && modelData.name.length > 0) ? modelData.name : modelData.type
    property int dragDeltaStart: (isSelected && timelineViewRoot.isDraggingMulti) ? timelineViewRoot.activeDragDeltaFrame : 0
    property int dragDeltaLayer: (isSelected && timelineViewRoot.isDraggingMulti) ? timelineViewRoot.activeDragDeltaLayer : 0

    signal clipMoved(int clipId, int deltaLayer, int deltaStartFrame, int duration)
    signal clipResized(int clipId, int deltaStartFrame, int deltaDuration, int unused)
    signal clipDoubleClicked(int clipId)

    x: (resizeDraftStart >= 0 ? resizeDraftStart : Math.max(0, modelData.startFrame + dragDeltaStart)) * scale
    y: Math.max(0, modelData.layer + dragDeltaLayer) * layerHeight
    width: (resizeDraftDuration >= 0 ? resizeDraftDuration : modelData.durationFrames) * scale
    height: layerHeight
    z: modelData.layer

    Rectangle {
        visible: clipDelegate.isSelected && (modelData.groupLayerCount > 0)
        x: 0
        y: layerHeight
        width: parent.width
        height: modelData.groupLayerCount * layerHeight
        color: Qt.rgba(palette.highlight.r, palette.highlight.g, palette.highlight.b, 0.18)
        border.color: Qt.rgba(palette.highlight.r, palette.highlight.g, palette.highlight.b, 0.55)
        border.width: 1
        z: -1
    }

    Rectangle {
        id: clipRect

        anchors.fill: parent
        anchors.bottomMargin: 2
        color: {
            var c = Workspace.currentTimeline ? Workspace.currentTimeline.getClipTypeColor(modelData.type) : "";
            if (c !== "")
                return isSelected ? Qt.lighter(c, 1.3) : c;

            return isSelected ? palette.highlight : Qt.darker(palette.highlight, 1.6);
        }
        border.color: isSelected ? palette.highlight : palette.midlight
        border.width: isSelected ? 2 : 1
        opacity: 1
        radius: 4

        Text {
            readonly property int padding: 4
            property real stickyX: Math.max(0, (timelineViewRoot ? timelineViewRoot.contentX : 0) - clipDelegate.x)

            anchors.verticalCenter: parent.verticalCenter
            text: clipDelegate.clipDisplayName
            color: "white"
            font.pixelSize: 10
            elide: Text.ElideRight
            x: Math.min(stickyX, parent.width - width - padding) + padding
            width: Math.min(implicitWidth, parent.width - padding * 2)
        }

        Canvas {
            id: waveformCanvas

            readonly property bool isAudio: modelData.type === "audio"
            property int waveRev: 0
            property bool _paintPending: false
            readonly property int displayDuration: {
                if (clipDelegate.resizeDraftDuration >= 0)
                    return clipDelegate.resizeDraftDuration;

                return modelData.durationFrames;
            }

            function _schedulePaint() {
                if (!isAudio)
                    return ;

                if (_paintPending)
                    return ;

                _paintPending = true;
                Qt.callLater(function() {
                    _paintPending = false;
                    waveformCanvas.requestPaint();
                });
            }

            anchors.fill: parent
            visible: isAudio
            opacity: 0.7
            onWidthChanged: _schedulePaint()
            onDisplayDurationChanged: _schedulePaint()
            onWaveRevChanged: _schedulePaint()
            onPaint: {
                var ctx = getContext("2d");
                ctx.clearRect(0, 0, width, height);
                if (!isAudio || width <= 0 || !Workspace.currentTimeline)
                    return ;

                var pw = Math.floor(width);
                var dur = displayDuration;
                if (pw <= 0 || dur <= 0)
                    return ;

                var peaks = Workspace.currentTimeline.getWaveformPeaks(modelData.id, pw, dur);
                if (!peaks || peaks.length === 0)
                    return ;

                var cy = height / 2;
                var maxH = cy - 2;
                ctx.strokeStyle = "rgba(255, 255, 255, 0.9)";
                ctx.lineWidth = 1;
                for (var i = 0; i < peaks.length / 2; i++) {
                    var pMin = peaks[i * 2];
                    var pMax = peaks[i * 2 + 1];
                    var yTop = cy - (pMax * maxH);
                    var yBottom = cy - (pMin * maxH);
                    // 振幅が極めて小さい場合でも1pxの線を表示する
                    if (yBottom - yTop < 1)
                        yBottom = yTop + 1;

                    ctx.beginPath();
                    ctx.moveTo(i + 0.5, yTop);
                    ctx.lineTo(i + 0.5, yBottom);
                    ctx.stroke();
                }
            }

            Connections {
                function onClipsChanged() {
                    waveformCanvas._schedulePaint();
                }

                target: Workspace.currentTimeline
            }

        }

        MouseArea {
            // Handled by parent if needed, or emit signal to request scroll
            // timelineFlickable.contentX = Math.max(0, timelineFlickable.contentX + (finalF - propF) * clipDelegate.scale);

            id: moveArea

            property int pressModifiers: 0
            property point dragStartScenePos: Qt.point(0, 0)
            property point pressScenePos: Qt.point(0, 0)
            property int initialLayer: 0
            property int initialFrame: 0
            property int lastProposedFrame: -1
            property int lastProposedLayer: -1
            property bool dragActive: false
            property real dragThreshold: 3
            property point lastScenePos: Qt.point(0, 0)
            property int lastModifiers: 0

            function updateDragFromScenePos(sp, modifiers) {
                var dX = sp.x - dragStartScenePos.x;
                var dY = sp.y - dragStartScenePos.y;
                var deltaFrame = Math.round(dX / clipDelegate.scale);
                var deltaLayer = Math.round(dY / layerHeight);
                var ignoreSnap = (modifiers & Qt.ShiftModifier);
                if (Workspace.currentTimeline && typeof Workspace.currentTimeline.resolveDragDelta === "function") {
                    var activeIds = (timelineViewRoot && timelineViewRoot.selectionVisualLatchIds) || [];
                    if (activeIds.length === 0 && Workspace.currentTimeline.selection)
                        activeIds = Workspace.currentTimeline.selection.selectedClipIds;

                    var res = Workspace.currentTimeline.resolveDragDelta(modelData.id, deltaFrame, deltaLayer, activeIds, timelineViewRoot.selectionMinFrame, timelineViewRoot.selectionMinLayer, timelineViewRoot.selectionMaxLayer, timelineViewRoot.layerCount);
                    var dF = res.x;
                    var dL = res.y;
                    if (!ignoreSnap)
                        dF = snapFrameFunc(initialFrame + dF, false) - initialFrame;

                    if (dF === timelineViewRoot.activeDragDeltaFrame && dL === timelineViewRoot.activeDragDeltaLayer)
                        return ;

                    timelineViewRoot.activeDragDeltaFrame = dF;
                    timelineViewRoot.activeDragDeltaLayer = dL;
                }
            }

            anchors.fill: parent
            anchors.leftMargin: clipResizeHandleWidth
            anchors.rightMargin: clipResizeHandleWidth
            acceptedButtons: Qt.LeftButton
            cursorShape: clipDelegate.isLayerLocked ? Qt.ForbiddenCursor : Qt.OpenHandCursor
            preventStealing: true
            onPressed: (mouse) => {
                timelineViewRoot.beginDragAutoScroll(function() {
                    if (dragActive)
                        updateDragFromScenePos(lastScenePos, lastModifiers);

                });
                if (clipDelegate.isLayerLocked)
                    return ;

                dragActive = false;
                pressModifiers = mouse.modifiers;
                // [FIX] REMOVED early selection logic here.
                // We rely on onReleased for both single-click and Ctrl-click,
                // to avoid state desync and input branching issues.
                // If dragging happens without selection, it will select it during drag or drop.
                // Wait! If dragging without selection, you drag an unselected clip?
                // The UX fix was exactly for that.
                // Let's bring it back BUT ONLY IF WE START DRAGGING!
                var sp = mapToItem(flickableContentItem, mouse.x, mouse.y);
                pressScenePos = sp;
                dragStartScenePos = sp;
                initialLayer = modelData.layer;
                initialFrame = modelData.startFrame;
                lastProposedFrame = -1;
                lastProposedLayer = -1;
            }
            onPositionChanged: (mouse) => {
                if (!pressed || clipDelegate.isLayerLocked)
                    return ;

                var sp = mapToItem(flickableContentItem, mouse.x, mouse.y);
                if (!dragActive) {
                    if (Math.abs(sp.x - pressScenePos.x) < dragThreshold && Math.abs(sp.y - pressScenePos.y) < dragThreshold)
                        return ;

                    dragActive = true;
                    if (!clipDelegate.isSelected && Workspace.currentTimeline)
                        Workspace.currentTimeline.handleClipClick(modelData.id, pressModifiers);

                    var minF = modelData.startFrame;
                    var minL = modelData.layer;
                    var maxL = modelData.layer;
                    if (Workspace.currentTimeline && Workspace.currentTimeline.selection) {
                        var ids = (timelineViewRoot && timelineViewRoot.selectionVisualLatchIds) || [];
                        if (ids.length === 0)
                            ids = Workspace.currentTimeline.selection.selectedClipIds;

                        if (ids.length > 0) {
                            minF = 1e+07;
                            minL = 1e+07;
                            maxL = -1;
                            for (var i = 0; i < Workspace.currentTimeline.clips.length; i++) {
                                var c = Workspace.currentTimeline.clips[i];
                                if (ids.includes(c.id)) {
                                    if (c.startFrame < minF)
                                        minF = c.startFrame;

                                    if (c.layer < minL)
                                        minL = c.layer;

                                    if (c.layer > maxL)
                                        maxL = c.layer;

                                }
                            }
                        }
                    }
                    timelineViewRoot.selectionMinFrame = minF;
                    timelineViewRoot.selectionMinLayer = minL;
                    timelineViewRoot.selectionMaxLayer = maxL;
                    timelineViewRoot.isDraggingMulti = true;
                    timelineViewRoot.activeDragDeltaFrame = 0;
                    timelineViewRoot.activeDragDeltaLayer = 0;
                }
                lastScenePos = sp;
                lastModifiers = mouse.modifiers;
                var vp = mapToItem(timelineViewRoot, mouse.x, mouse.y);
                timelineViewRoot.updateDragAutoScroll(vp);
                updateDragFromScenePos(sp, mouse.modifiers);
            }
            onReleased: (mouse) => {
                timelineViewRoot.endDragAutoScroll();
                if (!Workspace.currentTimeline)
                    return ;

                if (!dragActive) {
                    if (Workspace.currentTimeline)
                        Workspace.currentTimeline.handleClipClick(modelData.id, pressModifiers);

                    return ;
                }
                var deltaF = timelineViewRoot.activeDragDeltaFrame;
                var deltaL = timelineViewRoot.activeDragDeltaLayer;
                dragActive = false;
                // Emit relative movement FIRST so backend updates
                clipMoved(modelData.id, deltaL, deltaF, modelData.durationFrames);
                // Delay dropping the visual multi-drag state so that bindings
                // don't collapse before C++ model updates are fully propagated.
                var viewRoot = timelineViewRoot;
                Qt.callLater(function() {
                    if (viewRoot) {
                        viewRoot.isDraggingMulti = false;
                        viewRoot.activeDragDeltaFrame = 0;
                        viewRoot.activeDragDeltaLayer = 0;
                    }
                });
            }
            onDoubleClicked: {
                if (WindowManager)
                    WindowManager.raiseWindow("objectSettings");

            }
        }

        Rectangle {
            width: clipResizeHandleWidth
            height: parent.height
            anchors.left: parent.left
            color: "transparent"
            z: 10

            MouseArea {
                id: leftResizeArea

                property real startSceneX: 0 // Flickable contentItem 座標
                property int startFrame: 0
                property int startDuration: 0
                property bool resizing: false

                anchors.fill: parent
                cursorShape: Qt.SizeHorCursor
                hoverEnabled: true
                preventStealing: true
                onPressed: (mouse) => {
                    if (clipDelegate.isLayerLocked)
                        return ;

                    if (!clipDelegate.isSelected && Workspace.currentTimeline)
                        Workspace.currentTimeline.handleClipClick(modelData.id, mouse.modifiers);

                    var sp = mapToItem(flickableContentItem, mouse.x, mouse.y);
                    startSceneX = sp.x;
                    startFrame = modelData.startFrame;
                    startDuration = modelData.durationFrames;
                    resizing = true;
                    mouse.accepted = true;
                }
                onPositionChanged: (mouse) => {
                    if (!resizing)
                        return ;

                    var sp = mapToItem(flickableContentItem, mouse.x, mouse.y);
                    var delta = sp.x - startSceneX;
                    // 右端（終点）を固定して左端のみ動かす
                    var endFrame = startFrame + startDuration;
                    var rawNewStart = startFrame + delta / clipDelegate.scale;
                    var ignoreSnap = (mouse.modifiers & Qt.ShiftModifier);
                    var newStart = Math.max(0, snapFrameFunc(rawNewStart, ignoreSnap));
                    var newDur = endFrame - newStart;
                    var minDur = SettingsManager ? SettingsManager.value("minClipDurationFrames", 5) : 5;
                    if (newDur < minDur) {
                        newStart = endFrame - minDur;
                        newDur = minDur;
                    }
                    // ドラフトプロパティ経由で表示更新（バインディング破壊なし）
                    clipDelegate.resizeDraftStart = newStart;
                    clipDelegate.resizeDraftDuration = newDur;
                }
                onReleased: {
                    if (!resizing)
                        return ;

                    resizing = false;
                    if (Workspace.currentTimeline && clipDelegate.resizeDraftDuration > 0) {
                        var newStart = clipDelegate.resizeDraftStart >= 0 ? clipDelegate.resizeDraftStart : modelData.startFrame;
                        var deltaStart = newStart - startFrame;
                        var deltaDuration = clipDelegate.resizeDraftDuration - startDuration;
                        clipResized(modelData.id, deltaStart, deltaDuration, 0); // using params to pass delta
                    }
                    // ドラフト解除 → バインディングが自動で正値を返す
                    clipDelegate.resizeDraftStart = -1;
                    clipDelegate.resizeDraftDuration = -1;
                }
            }

        }

        Rectangle {
            width: clipResizeHandleWidth
            height: parent.height
            anchors.right: parent.right
            color: "transparent"
            z: 10

            MouseArea {
                id: rightResizeArea

                property real startSceneX: 0 // Flickable contentItem 座標
                property int startFrame: 0 // リサイズ開始時の startFrame
                property int startDuration: 0
                property bool resizing: false

                anchors.fill: parent
                cursorShape: Qt.SizeHorCursor
                hoverEnabled: true
                preventStealing: true
                onPressed: (mouse) => {
                    if (clipDelegate.isLayerLocked)
                        return ;

                    if (!clipDelegate.isSelected && Workspace.currentTimeline)
                        Workspace.currentTimeline.handleClipClick(modelData.id, mouse.modifiers);

                    var sp = mapToItem(flickableContentItem, mouse.x, mouse.y);
                    startSceneX = sp.x;
                    startFrame = modelData.startFrame;
                    startDuration = modelData.durationFrames;
                    resizing = true;
                    mouse.accepted = true;
                }
                onPositionChanged: (mouse) => {
                    if (!resizing)
                        return ;

                    var sp = mapToItem(flickableContentItem, mouse.x, mouse.y);
                    var delta = sp.x - startSceneX;
                    // 右端フレームをスナップ
                    var rawEndFrame = startFrame + (startDuration * clipDelegate.scale + delta) / clipDelegate.scale;
                    var ignoreSnap = (mouse.modifiers & Qt.ShiftModifier);
                    var snappedEndFrame = snapFrameFunc(rawEndFrame, ignoreSnap);
                    var minDur = SettingsManager ? SettingsManager.value("minClipDurationFrames", 5) : 5;
                    var newDur = Math.max(minDur, snappedEndFrame - startFrame);
                    // ドラフトプロパティ経由で表示更新（バインディング破壊なし）
                    clipDelegate.resizeDraftDuration = newDur;
                }
                onReleased: {
                    if (!resizing)
                        return ;

                    resizing = false;
                    if (Workspace.currentTimeline && clipDelegate.resizeDraftDuration > 0) {
                        var deltaDuration = clipDelegate.resizeDraftDuration - startDuration;
                        clipResized(modelData.id, 0, deltaDuration, 0);
                    }
                    // ドラフト解除 → バインディングが自動で正値を返す
                    clipDelegate.resizeDraftDuration = -1;
                }
            }

        }

    }

}

import "../common" as Common
import QtQuick
import QtQuick.Controls
import QtQuick.Layouts

Rectangle {
    id: headerRoot

    property int headerWidth: 60
    property int layerHeight: 30
    property int layerCount: 128
    property var syncFlickable: null // TimelineViewのFlickable
    // レイヤー状態管理 (内部保持)
    property var _layerStates: ({
    })

    // 外部への通知シグナル
    signal layerVisibilityChanged(int layer, bool visible)
    signal layerLockChanged(int layer, bool locked)

    function clamp(v, lo, hi) {
        return Math.max(lo, Math.min(hi, v));
    }

    function getLayerVisible(layer) {
        var state = _layerStates[layer];
        return state ? state.visible : true;
    }

    function getLayerLocked(layer) {
        var state = _layerStates[layer];
        return state ? state.locked : false;
    }

    function setLayerVisible(layer, visible) {
        if (!_layerStates[layer])
            _layerStates[layer] = {
            "visible": true,
            "locked": false
        };

        _layerStates[layer].visible = visible;
        layerVisibilityChanged(layer, visible);
        // 強制的に再評価を促す
        _layerStatesChanged();
    }

    function setLayerLocked(layer, locked) {
        if (!_layerStates[layer])
            _layerStates[layer] = {
            "visible": true,
            "locked": false
        };

        _layerStates[layer].locked = locked;
        layerLockChanged(layer, locked);
        _layerStatesChanged();
    }

    Layout.preferredWidth: headerWidth
    Layout.fillHeight: true
    color: palette.button
    z: 2

    Flickable {
        id: layerHeaderFlickable

        anchors.fill: parent
        contentHeight: layerCount * layerHeight
        // TimelineViewと同期
        contentY: syncFlickable ? syncFlickable.contentY : 0
        interactive: false // 独自のホイール処理を行うため
        clip: true

        Column {
            Repeater {
                model: layerCount

                // レイヤーボタン (AviUtl風)
                Button {
                    id: layerBtn

                    property int layerIndex: index
                    property bool isVisible: headerRoot.getLayerVisible(layerIndex)
                    property bool isLocked: headerRoot.getLayerLocked(layerIndex)

                    width: headerRoot.headerWidth
                    height: headerRoot.layerHeight
                    flat: true
                    // 左クリック: 表示/非表示トグル
                    onClicked: {
                        headerRoot.setLayerVisible(layerIndex, !isVisible);
                    }

                    // 右クリック: コンテキストメニュー
                    MouseArea {
                        anchors.fill: parent
                        acceptedButtons: Qt.RightButton
                        onClicked: {
                            layerMenu.layerIndex = layerBtn.layerIndex;
                            layerMenu.popup();
                        }
                    }

                    // 背景色: 非表示時は暗く、ロック時は赤みがかる
                    background: Rectangle {
                        color: {
                            if (!layerBtn.isVisible)
                                return Qt.darker(palette.button, 1.5);

                            if (layerBtn.isLocked)
                                return Qt.rgba(0.6, 0.3, 0.3, 1);

                            return (layerBtn.layerIndex % 2 == 0) ? palette.button : Qt.darker(palette.button, 1.1);
                        }
                        border.color: palette.mid
                        border.width: 1
                    }

                    // レイヤー番号表示
                    contentItem: Item {
                        Text {
                            anchors.centerIn: parent
                            text: (layerBtn.layerIndex + 1).toString()
                            color: {
                                if (!layerBtn.isVisible)
                                    return palette.mid;

                                if (layerBtn.isLocked)
                                    return "#ffcccc";

                                return palette.text;
                            }
                            font.pixelSize: 12
                            font.bold: layerBtn.isVisible && !layerBtn.isLocked
                        }

                        // 状態インジケーター (右上に小さな記号)
                        Row {
                            anchors.right: parent.right
                            anchors.top: parent.top
                            anchors.margins: 2
                            spacing: 2

                            Common.AviQtlIcon {
                                visible: layerBtn.isLocked
                                iconName: "lock_fill"
                                size: 10
                                color: "#ffcccc"
                            }

                            Common.AviQtlIcon {
                                visible: !layerBtn.isVisible
                                iconName: "eye_off_line"
                                size: 10
                                color: palette.mid
                            }

                        }

                    }

                }

            }

        }

    }

    // レイヤーコンテキストメニュー
    Menu {
        id: layerMenu

        property int layerIndex: 0

        Common.IconMenuItem {
            text: qsTr("表示/非表示を切り替え")
            iconName: headerRoot.getLayerVisible(layerMenu.layerIndex) ? "eye_off_line" : "eye_line"
            onTriggered: {
                var visible = headerRoot.getLayerVisible(layerMenu.layerIndex);
                headerRoot.setLayerVisible(layerMenu.layerIndex, !visible);
            }
        }

        MenuSeparator {
        }

        Common.IconMenuItem {
            text: {
                var locked = headerRoot.getLayerLocked(layerMenu.layerIndex);
                return locked ? qsTr("ロックを解除") : qsTr("ロック");
            }
            iconName: headerRoot.getLayerLocked(layerMenu.layerIndex) ? "lock_unlock_line" : "lock_line"
            onTriggered: {
                var locked = headerRoot.getLayerLocked(layerMenu.layerIndex);
                headerRoot.setLayerLocked(layerMenu.layerIndex, !locked);
            }
        }

        MenuSeparator {
        }

        Common.IconMenuItem {
            text: qsTr("すべて表示")
            iconName: "eye_line"
            onTriggered: {
                for (var i = 0; i < headerRoot.layerCount; i++) {
                    headerRoot.setLayerVisible(i, true);
                }
            }
        }

        Common.IconMenuItem {
            text: qsTr("すべて非表示")
            iconName: "eye_off_line"
            onTriggered: {
                for (var i = 0; i < headerRoot.layerCount; i++) {
                    headerRoot.setLayerVisible(i, false);
                }
            }
        }

    }

    // 縦スクロール専用マウスエリア
    MouseArea {
        anchors.fill: parent
        acceptedButtons: Qt.NoButton
        z: -1
        hoverEnabled: true
        onWheel: (wheel) => {
            if (!syncFlickable)
                return ;

            var dy = wheel.angleDelta.y;
            if (wheel.pixelDelta && wheel.pixelDelta.y !== 0)
                dy = wheel.pixelDelta.y * 10;

            var nextY = syncFlickable.contentY - dy;
            var maxY = Math.max(0, syncFlickable.contentHeight - syncFlickable.height);
            syncFlickable.contentY = clamp(nextY, 0, maxY);
            wheel.accepted = true;
        }
    }

}

import "../common" as Common
import QtQuick
import QtQuick.Controls
import QtQuick.Layouts

Rectangle {
    id: rulerRoot

    // 外部から注入される依存プロパティ
    property var targetFlickable: null
    property int rulerHeight: 32
    property int timeWidth: 60
    property double fps: 60
    property alias canvas: rulerCanvas

    // ユーティリティ
    function pxToFrame(px, contentX) {
        var scale = Workspace.currentTimeline ? Workspace.currentTimeline.timelineScale : 1;
        var x = px + contentX;
        return Math.max(0, Math.round(x / scale));
    }

    function clamp(v, lo, hi) {
        return Math.max(lo, Math.min(hi, v));
    }

    function zoomAt(wheel, zoomFactor) {
        if (!Workspace.currentTimeline || !targetFlickable)
            return ;

        var oldScale = Workspace.currentTimeline.timelineScale;
        var newScale = clamp(oldScale * zoomFactor, 0.1, 20);
        if (Math.abs(newScale - oldScale) < 1e-06)
            return ;

        var mouseX = wheel.x !== undefined ? wheel.x : (wheel.position ? wheel.position.x : 0);
        var anchorFrame = (targetFlickable.contentX + mouseX - timeWidth) / oldScale; // timeWidth補正
        Workspace.currentTimeline.timelineScale = newScale;
        // ズーム後の位置補正
        var newContentX = anchorFrame * newScale - mouseX + timeWidth;
        var maxX = Math.max(0, targetFlickable.contentWidth - targetFlickable.width);
        targetFlickable.contentX = clamp(newContentX, 0, maxX);
    }

    Layout.fillWidth: true
    Layout.preferredHeight: rulerHeight
    color: palette.window
    z: 10

    // Canvas再描画トリガー
    Connections {
        function onContentXChanged() {
            rulerCanvas.requestPaint();
        }

        target: targetFlickable
    }

    RowLayout {
        anchors.fill: parent
        spacing: 0

        // 左上の空白（レイヤーヘッダーの上）
        Rectangle {
            Layout.preferredWidth: timeWidth
            Layout.fillHeight: true
            color: palette.base
            border.color: palette.mid
            border.width: 1
            z: 100

            Text {
                anchors.centerIn: parent
                text: Workspace.currentTimeline && Workspace.currentTimeline.transport ? Workspace.currentTimeline.transport.currentFrame + "f" : "0f"
                font.pixelSize: 11
                font.bold: true
                color: palette.highlight
            }

        }

        // 定規本体
        Item {
            Layout.fillWidth: true
            Layout.fillHeight: true
            clip: true

            Canvas {
                id: rulerCanvas

                property double scale: Workspace.currentTimeline ? Workspace.currentTimeline.timelineScale : 1
                property double offsetX: targetFlickable ? targetFlickable.contentX : 0
                property int fpsInt: Math.round(rulerRoot.fps)

                anchors.fill: parent
                onScaleChanged: requestPaint()
                onOffsetXChanged: requestPaint()
                onWidthChanged: requestPaint()
                onHeightChanged: requestPaint()
                onPaint: {
                    if (width <= 0 || height <= 0 || scale <= 0)
                        return ;

                    var ctx = getContext("2d");
                    ctx.clearRect(0, 0, width, height);
                    if (!Workspace.currentTimeline)
                        return ;

                    var viewWidth = width;
                    var viewOffsetX = offsetX;
                    // 簡易的なグリッド描画（詳細は元のロジックを維持）
                    var frameInterval = 60;
                    // 仮
                    if (scale > 5)
                        frameInterval = 10;
                    else if (scale > 1)
                        frameInterval = 30;
                    else if (scale > 0.5)
                        frameInterval = 60;
                    else
                        frameInterval = 300;
                    var startFrame = Math.floor(viewOffsetX / scale);
                    var endFrame = Math.ceil((viewOffsetX + viewWidth) / scale);
                    var alignedStart = Math.floor(startFrame / frameInterval) * frameInterval;
                    ctx.strokeStyle = palette.text;
                    ctx.fillStyle = palette.text;
                    ctx.lineWidth = 1;
                    ctx.font = "10px sans-serif";
                    for (var f = alignedStart; f <= endFrame; f += frameInterval) {
                        var pixelX = f * scale - viewOffsetX;
                        var isSecond = (f % fpsInt === 0);
                        // 大目盛
                        ctx.beginPath();
                        ctx.moveTo(pixelX, 15);
                        ctx.lineTo(pixelX, height);
                        ctx.stroke();
                        if (isSecond) {
                            // 時:分:秒 形式の時間表示
                            var totalSeconds = f / fpsInt;
                            var hours = Math.floor(totalSeconds / 3600);
                            var minutes = Math.floor((totalSeconds % 3600) / 60);
                            var seconds = Math.floor(totalSeconds % 60);
                            var timeLabel;
                            if (hours > 0)
                                timeLabel = hours + ":" + ("0" + minutes).slice(-2) + ":" + ("0" + seconds).slice(-2);
                            else if (minutes > 0)
                                timeLabel = minutes + ":" + ("0" + seconds).slice(-2);
                            else
                                timeLabel = seconds + "s";
                            ctx.fillStyle = palette.text;
                            ctx.fillText(timeLabel, pixelX + 3, 12);
                            // フレーム番号を小さく表示
                            ctx.font = "8px sans-serif";
                            ctx.fillStyle = palette.mid;
                            ctx.fillText(f + "f", pixelX + 3, 24);
                            ctx.font = "10px sans-serif";
                        } else {
                            // フレーム数テキスト（秒単位以外）
                            ctx.fillStyle = palette.text;
                            ctx.fillText(f, pixelX + 2, 12);
                        }
                    }
                }

                Connections {
                    function onCurrentTimelineChanged() {
                        rulerCanvas.requestPaint();
                    }

                    target: Workspace
                }

            }

            Rectangle {
                id: rulerPlayhead

                x: Math.round(((Workspace.currentTimeline && Workspace.currentTimeline.transport ? Workspace.currentTimeline.transport.currentFrame : 0) * (Workspace.currentTimeline ? Workspace.currentTimeline.timelineScale : 1)) - (targetFlickable ? targetFlickable.contentX : 0))
                y: 0
                width: 2
                height: parent.height
                color: palette.highlight
                z: 10
            }
            // マウス操作（スクラブ & ズーム）

            // マウス操作（スクラブ & ズーム）
            MouseArea {
                anchors.fill: parent
                hoverEnabled: true
                acceptedButtons: Qt.LeftButton | Qt.RightButton
                onPressed: (mouse) => {
                    if (mouse.button === Qt.LeftButton && targetFlickable && Workspace.currentTimeline && Workspace.currentTimeline.transport) {
                        Workspace.currentTimeline.transport.beginScrub();
                        Workspace.currentTimeline.transport.scrubTo(pxToFrame(mouse.x, targetFlickable.contentX));
                    }
                }
                onPositionChanged: (mouse) => {
                    if (pressed && (mouse.buttons & Qt.LeftButton) && targetFlickable && Workspace.currentTimeline && Workspace.currentTimeline.transport)
                        Workspace.currentTimeline.transport.scrubTo(pxToFrame(mouse.x, targetFlickable.contentX));

                }
                onReleased: (mouse) => {
                    if (mouse.button === Qt.LeftButton && Workspace.currentTimeline && Workspace.currentTimeline.transport)
                        Workspace.currentTimeline.transport.endScrub();

                }
                onWheel: (wheel) => {
                    var dy = (wheel.angleDelta.y !== 0) ? wheel.angleDelta.y : (wheel.pixelDelta.y * 10);
                    var zoomFactor = (dy > 0) ? 1.1 : 0.9;
                    zoomAt(wheel, zoomFactor);
                    wheel.accepted = true;
                }
            }

        }

    }

}

import QtQuick

Canvas {
    id: timelineGrid

    property real contentX: 0
    property real contentY: 0
    property real gridInterval: 1
    property int layerCount: 128
    property int layerHeight: 30
    property real scale: Workspace.currentTimeline ? Workspace.currentTimeline.timelineScale : 1
    property var gridSettings: ({
        "mode": "Auto",
        "bpm": 120,
        "offset": 0,
        "interval": 10,
        "subdivision": 4
    })

    onContentXChanged: requestPaint()
    onContentYChanged: requestPaint()
    onGridIntervalChanged: requestPaint()
    onGridSettingsChanged: requestPaint()
    onScaleChanged: requestPaint()
    onWidthChanged: requestPaint()
    onHeightChanged: requestPaint()
    anchors.fill: parent
    onPaint: {
        if (width <= 0 || height <= 0 || scale <= 0)
            return ;

        var ctx = getContext("2d");
        ctx.clearRect(0, 0, width, height);
        ctx.lineWidth = 1;
        // 水平区切り線
        ctx.strokeStyle = Qt.rgba(0.5, 0.5, 0.5, 0.2);
        var startY = contentY;
        for (var i = 0; i < layerCount; i++) {
            var ly = i * layerHeight - startY;
            if (ly < -layerHeight || ly > height)
                continue;

            ctx.beginPath();
            ctx.moveTo(0, ly);
            ctx.lineTo(width, ly);
            ctx.stroke();
        }
        if (!Workspace.currentTimeline)
            return ;

        // 垂直グリッド線
        var currentScale = scale;
        var currentContentX = contentX;
        var step = gridInterval;
        if (step <= 0)
            return ;

        var offsetF = (gridSettings.mode === "BPM" && Workspace.currentTimeline.project) ? gridSettings.offset * Workspace.currentTimeline.project.fps : 0;
        var isBpm = (gridSettings.mode === "BPM");
        var bpmDiv = isBpm ? (currentScale > 3 ? 4 : currentScale > 1.5 ? 2 : 1) : 1;
        var startN = Math.ceil((Math.floor(currentContentX / currentScale) - offsetF) / step);
        var endN = Math.floor((Math.ceil((currentContentX + width) / currentScale) - offsetF) / step);
        for (var n = startN; n <= endN; n++) {
            var f = offsetF + n * step;
            var x = f * currentScale - currentContentX;
            ctx.beginPath();
            if (isBpm) {
                var isMeasure = (n % (gridSettings.subdivision * bpmDiv) === 0);
                var isBeat = (n % bpmDiv === 0);
                if (isMeasure) {
                    ctx.strokeStyle = Qt.rgba(0.5, 0.8, 1, 0.5);
                    ctx.lineWidth = 1.5;
                } else if (isBeat) {
                    ctx.strokeStyle = Qt.rgba(0.5, 0.5, 0.5, 0.3);
                    ctx.lineWidth = 1;
                } else {
                    ctx.strokeStyle = Qt.rgba(0.5, 0.5, 0.5, 0.15);
                    ctx.lineWidth = 1;
                }
            } else {
                ctx.strokeStyle = Qt.rgba(0.5, 0.5, 0.5, 0.15);
                ctx.lineWidth = 1;
            }
            ctx.moveTo(x, 0);
            ctx.lineTo(x, height);
            ctx.stroke();
        }
    }

    Connections {
        function onCurrentTimelineChanged() {
            timelineGrid.requestPaint();
        }

        target: Workspace
    }

}

import "../common" as Common
import QtQuick
import QtQuick.Controls
import QtQuick.Layouts

ScrollView {
    id: timelineViewRoot

    property alias flickable: timelineFlickable
    property alias contentX: timelineFlickable.contentX
    property alias contentY: timelineFlickable.contentY
    property int layerHeight: 30
    property int layerCount: 128
    property int clipResizeHandleWidth: 6
    property var getLayerLocked: function(layer) {
        return false;
    }
    property int contextClickFrame: 0
    property int contextClickLayer: 0
    property bool boxSelecting: false
    property point boxSelectionStart: Qt.point(0, 0)
    property point boxSelectionCurrent: Qt.point(0, 0)
    property real boxSelectionThreshold: 6
    property bool boxSelectionAdditive: false
    property int activeDragDeltaFrame: 0
    property bool autoScrollSuspended: false
    property int activeDragDeltaLayer: 0
    property bool isDraggingMulti: false
    property int selectionMinFrame: 0
    property var selectionVisualLatchIds: []
    property int selectionMinLayer: 0
    property int selectionMaxLayer: 0
    property bool dragAutoScrollActive: false
    property point dragViewportPos: Qt.point(-1, -1)
    property real dragScrollEdge: 48
    property real dragScrollStep: 24
    property var dragAutoScrollCallback: null
    property var currentSceneData: {
        if (!Workspace.currentTimeline || !Workspace.currentTimeline.scenes)
            return null;

        for (var i = 0; i < Workspace.currentTimeline.scenes.length; i++) {
            if (Workspace.currentTimeline.scenes[i].id === Workspace.currentTimeline.currentSceneId)
                return Workspace.currentTimeline.scenes[i];

        }
        return null;
    }
    property bool enableSnap: currentSceneData && currentSceneData.enableSnap !== undefined ? currentSceneData.enableSnap : (SettingsManager.settings ? SettingsManager.settings.enableSnap : true)
    property int magneticSnapRange: currentSceneData && currentSceneData.magneticSnapRange !== undefined ? currentSceneData.magneticSnapRange : (SettingsManager.settings ? SettingsManager.value("magneticSnapRange", 10) : 10)
    property int tailPaddingFrames: 120
    property var gridSettings: {
        if (currentSceneData)
            return {
            "mode": currentSceneData.gridMode || "Auto",
            "bpm": currentSceneData.gridBpm || 120,
            "offset": currentSceneData.gridOffset || 0,
            "interval": currentSceneData.gridInterval || 10,
            "subdivision": currentSceneData.gridSubdivision || 4
        };

        return {
            "mode": "Auto",
            "bpm": 120,
            "offset": 0,
            "interval": 10,
            "subdivision": 4
        };
    }
    readonly property int maxClipEndFrame: {
        var maxEnd = 0;
        var clipList = (Workspace.currentTimeline && Workspace.currentTimeline.clips) ? Workspace.currentTimeline.clips : [];
        for (var i = 0; i < clipList.length; i++) {
            var end = clipList[i].startFrame + clipList[i].durationFrames;
            if (end > maxEnd)
                maxEnd = end;

        }
        return maxEnd;
    }
    readonly property int timelineLengthFrames: Math.max(100, maxClipEndFrame + tailPaddingFrames)

    function beginDragAutoScroll(callback) {
        dragAutoScrollCallback = callback;
        dragAutoScrollActive = true;
    }

    function updateDragAutoScroll(posInViewport) {
        dragViewportPos = posInViewport;
    }

    function endDragAutoScroll() {
        dragAutoScrollActive = false;
        dragAutoScrollCallback = null;
    }

    function syncBoxSelectionPreview() {
        if (!Workspace.currentTimeline)
            return ;

        var scale = Workspace.currentTimeline.timelineScale;
        var f1 = Math.floor(boxSelectionStart.x / scale);
        var f2 = Math.ceil(boxSelectionCurrent.x / scale);
        var l1 = Math.floor(boxSelectionStart.y / layerHeight);
        var l2 = Math.floor(boxSelectionCurrent.y / layerHeight);
        Workspace.currentTimeline.updateSelectionPreview(f1, f2, l1, l2, boxSelectionAdditive);
    }

    function clamp(v, lo, hi) {
        return Math.max(lo, Math.min(hi, v));
    }

    function getGridInterval() {
        if (!Workspace.currentTimeline)
            return 1;

        var scale = Workspace.currentTimeline.timelineScale;
        var projectFps = (Workspace.currentTimeline.project && Workspace.currentTimeline.project.fps) ? Workspace.currentTimeline.project.fps : 60;
        if (gridSettings.mode === "BPM") {
            var beatFrames = projectFps / (gridSettings.bpm / 60);
            var bpmDiv = scale > 3 ? 4 : scale > 1.5 ? 2 : 1;
            return beatFrames / bpmDiv;
        }
        if (gridSettings.mode === "Frame")
            return gridSettings.interval;

        // Auto
        if (scale < 0.5)
            return Math.ceil(projectFps);

        if (scale < 1.5)
            return 10;

        if (scale < 3)
            return 5;

        return 1;
    }

    function snapFrame(frame, ignoreSnap) {
        if (!enableSnap || ignoreSnap)
            return Math.max(0, Math.round(frame));

        // グリッド無視時は整数丸めのみ
        var step = getGridInterval();
        var offset = (gridSettings.mode === "BPM" && Workspace.currentTimeline && Workspace.currentTimeline.project) ? gridSettings.offset * Workspace.currentTimeline.project.fps : 0;
        return Math.max(0, Math.round((Math.round((frame - offset) / step) * step) + offset));
    }

    clip: true
    ScrollBar.horizontal.policy: ScrollBar.AlwaysOn
    ScrollBar.vertical.policy: ScrollBar.AlwaysOn

    Flickable {
        // unified loop handles viewport updates now
        id: timelineFlickable

        contentWidth: Math.max(width, timelineLengthFrames * (Workspace.currentTimeline ? Workspace.currentTimeline.timelineScale : 1))
        contentHeight: layerCount * layerHeight
        interactive: true
        onMovementStarted: timelineViewRoot.autoScrollSuspended = true

        Timer {
            id: renderTimer

            interval: 16
            repeat: true
            running: true // Unified render loop
            onTriggered: {
                if (!Workspace.currentTimeline)
                    return ;

                // 1. Viewport sync
                if (typeof Workspace.currentTimeline.updateViewport === "function")
                    Workspace.currentTimeline.updateViewport(timelineFlickable.contentX, timelineFlickable.contentY);

                if (timelineViewRoot.ScrollBar.horizontal && timelineViewRoot.ScrollBar.horizontal.pressed)
                    timelineViewRoot.autoScrollSuspended = true;

                if (timelineViewRoot.ScrollBar.vertical && timelineViewRoot.ScrollBar.vertical.pressed)
                    timelineViewRoot.autoScrollSuspended = true;

                // 2. Playhead auto-scroll (Page turn)
                if (Workspace.currentTimeline.transport && Workspace.currentTimeline.transport.isPlaying && !timelineViewRoot.autoScrollSuspended) {
                    let viewportWidth = timelineFlickable.width;
                    let playheadX = Workspace.currentTimeline.transport.currentFrame * Workspace.currentTimeline.timelineScale;
                    let left = timelineFlickable.contentX;
                    let right = left + viewportWidth;
                    let margin = 24;
                    if (playheadX < left || playheadX >= right - margin) {
                        let nextPage = Math.floor(playheadX / Math.max(1, viewportWidth));
                        let maxX = Math.max(0, timelineFlickable.contentWidth - viewportWidth);
                        timelineFlickable.contentX = clamp(nextPage * viewportWidth, 0, maxX);
                    }
                }
                // 3. Drag auto-scroll
                if (timelineViewRoot.dragAutoScrollActive) {
                    let dx = 0;
                    let dy = 0;
                    let edge = timelineViewRoot.dragScrollEdge;
                    let step = timelineViewRoot.dragScrollStep;
                    if (timelineViewRoot.dragViewportPos.x < edge)
                        dx = -step;
                    else if (timelineViewRoot.dragViewportPos.x > timelineFlickable.width - edge)
                        dx = step;
                    if (timelineViewRoot.dragViewportPos.y < edge)
                        dy = -step;
                    else if (timelineViewRoot.dragViewportPos.y > timelineFlickable.height - edge)
                        dy = step;
                    if (dx !== 0 || dy !== 0) {
                        let maxX = Math.max(0, timelineFlickable.contentWidth - timelineFlickable.width);
                        let maxY = Math.max(0, timelineFlickable.contentHeight - timelineFlickable.height);
                        timelineFlickable.contentX = clamp(timelineFlickable.contentX + dx, 0, maxX);
                        timelineFlickable.contentY = clamp(timelineFlickable.contentY + dy, 0, maxY);
                        if (timelineViewRoot.dragAutoScrollCallback)
                            timelineViewRoot.dragAutoScrollCallback();

                    }
                }
            }
        }

        Connections {
            function onTimelineScaleChanged() {
            }

            target: Workspace.currentTimeline ?? null
        }

        Connections {
            function onIsPlayingChanged() {
                if (Workspace.currentTimeline.transport.isPlaying)
                    timelineViewRoot.autoScrollSuspended = false;

            }

            target: Workspace.currentTimeline && Workspace.currentTimeline.transport ? Workspace.currentTimeline.transport : null
        }

        Item {
            x: timelineFlickable.contentX
            y: timelineFlickable.contentY
            width: timelineFlickable.width
            height: timelineFlickable.height
            z: -1

            TimelineGrid {
                id: timelineGrid

                anchors.fill: parent
                width: timelineFlickable.width
                height: timelineFlickable.height
                contentX: timelineFlickable.contentX
                contentY: timelineFlickable.contentY
                gridInterval: timelineViewRoot.getGridInterval()
                layerCount: timelineViewRoot.layerCount
                layerHeight: timelineViewRoot.layerHeight
                gridSettings: timelineViewRoot.gridSettings
            }

        }

        Repeater {
