#version 440
layout(location=0) in vec2 qt_TexCoord0;
layout(location=0) out vec4 fragColor;
layout(std140, binding=0) uniform buf {
    mat4  qt_Matrix;
    float qt_Opacity;
    float radius;
    float brightness;
    float targetWidth;
    float targetHeight;
};
layout(binding=1) uniform sampler2D source;
const float GOLDEN_ANGLE = 2.399963229728;
const int   MAX_SAMPLES  = 64;
void main() {
    if (radius < 0.5) {
        fragColor = texture(source, qt_TexCoord0) * qt_Opacity;
        return;
    }
    vec2  texel = vec2(radius / targetWidth, radius / targetHeight);
    vec4  sum   = vec4(0.0);
    int   n     = MAX_SAMPLES;
    for (int i = 0; i < n; i++) {
        float r     = sqrt(float(i + 1) / float(n + 1));
        float theta = float(i) * GOLDEN_ANGLE;
        vec2  off   = vec2(cos(theta), sin(theta)) * r * texel;
        vec4  s     = texture(source, qt_TexCoord0 + off);
        float luma  = dot(s.rgb, vec3(0.299, 0.587, 0.114));
        float boost = 1.0 + brightness * luma * 0.05;
        sum += s * boost;
    }
    fragColor = (sum / float(n)) * qt_Opacity;
}

#version 440
layout(location=0) in vec2 qt_TexCoord0;
layout(location=0) out vec4 fragColor;
layout(std140, binding=0) uniform buf {
    mat4  qt_Matrix;
    float qt_Opacity;
};
layout(binding=1) uniform sampler2D source;
layout(binding=2) uniform sampler2D maskSource;
void main() {
    vec4 blurred  = texture(source,     qt_TexCoord0);
    vec4 original = texture(maskSource, qt_TexCoord0);
    fragColor = vec4(blurred.rgb, blurred.a * original.a) * qt_Opacity;
}

#version 440
layout(location = 0) in vec2 qt_TexCoord0;
layout(location = 0) out vec4 fragColor;
layout(binding = 1) uniform sampler2D source;
layout(std140, binding = 0) uniform buf {
    mat4 qt_Matrix;
    float qt_Opacity;
    float size;
    float targetWidth;
    float targetHeight;
};

void main() {
    vec2 tc = qt_TexCoord0;

    if (size <= 1.0) {
        fragColor = texture(source, tc) * qt_Opacity;
        return;
    }

    // ピクセル座標に変換
    float px = tc.x * targetWidth;
    float py = tc.y * targetHeight;

    // 指定サイズで量子化（モザイクのブロック中心座標を計算）
    float mx = floor(px / size) * size + (size * 0.5);
    float my = floor(py / size) * size + (size * 0.5);

    vec2 mosaicTc = vec2(mx / targetWidth, my / targetHeight);

    fragColor = texture(source, mosaicTc) * qt_Opacity;
}

