#version 440
layout(location=0) in vec2 qt_TexCoord0;
layout(location=0) out vec4 fragColor;
layout(std140, binding=0) uniform buf {
    mat4  qt_Matrix;
    float qt_Opacity;
    float samples;
    float strength;
    float centerX;
    float centerY;
    float targetWidth;
    float targetHeight;
};
layout(binding=1) uniform sampler2D source;
void main() {
    vec2  center = vec2(0.5 + centerX / targetWidth,
                        0.5 - centerY / targetHeight);
    vec2  dir    = qt_TexCoord0 - center;
    int   n      = max(1, int(samples));
    float step   = strength / float(n) * 0.002;
    vec4  sum    = vec4(0.0);
    for (int i = 0; i < n; i++) {
        float t   = float(i) / float(max(n - 1, 1));
        vec2  uv  = qt_TexCoord0 - dir * t * step * float(n);
        sum += texture(source, clamp(uv, vec2(0.0), vec2(1.0)));
    }
    fragColor = (sum / float(n)) * qt_Opacity;
}

#version 440
layout(location = 0) in vec2 qt_TexCoord0;
layout(location = 0) out vec4 fragColor;
layout(binding = 1) uniform sampler2D source;
layout(std140, binding = 0) uniform buf {
    mat4 qt_Matrix;
    float qt_Opacity;
    float xStrength;
    float yStrength;
    float time;
    float targetWidth;
    float targetHeight;
};

// 簡易的な乱数生成
float rand(vec2 co) {
    return fract(sin(dot(co.xy, vec2(12.9898, 78.233))) * 43758.5453);
}

void main() {
    vec2 tc = qt_TexCoord0;

    // 時間に基づいてランダムなオフセットを生成
    // floor(time) を使うことで、フレームごとに不連続な動きにする
    float t = floor(time);
    float offsetX = (rand(vec2(t, 0.0)) - 0.5) * 2.0 * (xStrength / targetWidth);
    float offsetY = (rand(vec2(0.0, t)) - 0.5) * 2.0 * (yStrength / targetHeight);

    vec2 newTc = tc + vec2(offsetX, offsetY);

    fragColor = texture(source, newTc) * qt_Opacity;
}

