        return (d.label && d.label !== "") ? d.label : (d.param || d.name || qsTr("パラメータ"));
    }

    function _resolveSwatchColor(val) {
        if (!val || typeof val !== "string")
            return "#ffffff";

        var v = val.trim();
        if (!v.startsWith("{"))
            return v;

        try {
            var obj = JSON.parse(v);
            if (obj.stops && obj.stops.length > 0)
                return obj.stops[0].color;

        } catch (e) {
        }
        return "#ffffff";
    }

