        var found = false;
        for (var i = kfs.length - 1; i >= 0; i--) {
            if (kfs[i].frame <= cur) {
                s = kfs[i].frame;
                e = (i + 1 < kfs.length) ? kfs[i + 1].frame : total;
                found = true;
                break;
