import "Logger.js" as Logger
import QtQuick
import QtQuick3D

Node {
    id: loader

    property url source
    property var properties: ({
    })
    property QtObject item: null
    property int status: Loader.Null
    property string errorString: ""
    // 外部からコンポーネント取得関数を注入可能にする
    // function(url) -> Component
    property var componentFactory: null
    property Component _component: null

    function _applyProperties() {
        if (!item || !properties)
            return ;

        for (var key in properties) {
            if (item.hasOwnProperty(key) || (key in item))
                item[key] = properties[key];

        }
    }

    function _load() {
        if (item) {
            item.destroy();
            item = null;
        }
        _component = null;
        status = Loader.Loading;
        errorString = "";
        if (source == "") {
            status = Loader.Null;
            return ;
        }
        var comp = null;
        if (componentFactory && typeof componentFactory === "function")
            comp = componentFactory(source);
        else
            comp = Qt.createComponent(source, Component.Asynchronous);
        _component = comp;
        _processStatus();
    }

    function _processStatus() {
        if (!_component)
            return ;

        status = _component.status;
        if (status === Component.Ready) {
            item = _component.createObject(loader, properties);
            _applyProperties();
        } else if (status === Component.Error) {
            errorString = _component.errorString();
            Logger.log(qsTr("[NodeLoader] コンポーネントエラー: %1").arg(errorString));
        }
    }

    onSourceChanged: _load()
    onPropertiesChanged: _applyProperties()

    Connections {
        function onStatusChanged() {
            loader._processStatus();
        }

        target: _component
    }

}

import QtQuick

Item {
    id: renderer

    required property Item originalSource
    required property var effectModels
    required property int relFrame
    property var clipEvalParams: ({
    })
    property int _paramRev: 0
    property alias output: textureSource
    readonly property Item finalItem: textureSource.sourceItem

    width: originalSource ? originalSource.width : 1
    height: originalSource ? originalSource.height : 1

    Item {
        id: fallbackItem

        width: 1
        height: 1
        visible: true
        opacity: 0
    }

    Repeater {
        id: effectChain

        model: renderer.effectModels

        Loader {
            id: effectLoader

            property Item inputSource: {
                if (index === 0)
                    return renderer.originalSource;

                var prev = effectChain.itemAt(index - 1);
                if (prev && prev.status === Loader.Ready)
                    return prev.item;

                return renderer.originalSource;
            }

            function _syncAll() {
                if (!item)
                    return ;

                if ("source" in item)
                    item.source = inputSource;

                if ("params" in item)
                    item.params = modelData.params;

                if ("effectModel" in item)
                    item.effectModel = modelData;

                if ("frame" in item)
                    item.frame = renderer.relFrame;

                if ("clipEvalParams" in item)
                    item.clipEvalParams = Qt.binding(function() {
                    return renderer.clipEvalParams;
                });

                if ("_paramRev" in item)
                    item._paramRev = Qt.binding(function() {
                    return renderer._paramRev;
                });

            }

            // rendererInstance のサイズに追従させ、item (BaseEffect) のサイズを確定させる
            anchors.fill: parent
            active: modelData.enabled
            source: modelData.qmlSource
            onLoaded: _syncAll()
            onInputSourceChanged: {
                if (status === Loader.Ready) {
                    if ("source" in item)
                        item.source = inputSource;

                }
            }

            Connections {
                function onRelFrameChanged() {
                    if (effectLoader.status === Loader.Ready && effectLoader.item && "frame" in effectLoader.item)
                        effectLoader.item.frame = renderer.relFrame;

                }

                target: renderer
            }

            Connections {
                function onParamsChanged() {
                    if (effectLoader.status === Loader.Ready && effectLoader.item && "params" in effectLoader.item)
                        effectLoader.item.params = modelData.params;

                }

                target: modelData
            }

        }

    }

    ShaderEffectSource {
        id: textureSource

        function findFinalOutput(defaultSource) {
            for (var i = effectChain.count - 1; i >= 0; i--) {
                var loader = effectChain.itemAt(i);
                // width/height チェックを除去: anchors.fill: parent で親に追従するため
                // サイズが 0 の場合は item が存在することだけを確認する
                if (loader && loader.status === Loader.Ready && loader.active && loader.item)
                    return loader.item;

            }
            return defaultSource;
        }

        sourceItem: {
            if (!renderer.originalSource || renderer.originalSource.width <= 0 || renderer.originalSource.height <= 0)
                return fallbackItem;

            if (effectChain.count > 0)
                return findFinalOutput(renderer.originalSource);

            return renderer.originalSource;
        }
        visible: false
        live: true
        hideSource: true
        recursive: false
    }

}

import QtQuick
import QtQuick.Controls
import QtQuick.Layouts

// AviUtl風の中間点対応パラメータコントロール
RowLayout {
    id: root

    property string paramName: qsTr("パラメータ")
    property real minValue: 0
    property real maxValue: 100
    property real startValue: 0
    property real endValue: 0
    property int decimals: 0
    property string interpolationType: "constant"
    property bool isRangeMode: Math.abs(startValue - endValue) > 0.001
    property bool interpolationSelected: interpolationType !== "" && interpolationType !== "constant"
    property bool rightLinked: !interpolationSelected
    property bool rightInteractive: root.enabled && root.isRangeMode && root.interpolationSelected

    signal startValueModified(real value)
    signal endValueModified(real value)
    signal paramButtonClicked()

    function formatValue(val) {
        var num = Number(val);
        if (isNaN(num))
            num = 0;

        return root.decimals === 0 ? num.toFixed(0) : num.toFixed(root.decimals);
    }

    function syncRightDisplay(val) {
        var text = formatValue(val);
        if (rightValueField.text !== text)
            rightValueField.text = text;

    }

    function pushLeftValue(val) {
        var text = formatValue(val);
        if (leftValueField.text !== text)
            leftValueField.text = text;

        root.startValueModified(val);
        if (root.rightLinked) {
            syncRightDisplay(val);
            root.endValueModified(val);
        }
    }

    spacing: 8
    Component.onCompleted: {
        if (root.rightLinked)
            syncRightDisplay(root.startValue);

    }
    onStartValueChanged: {
        var text = formatValue(root.startValue);
        if (leftValueField.text !== text)
            leftValueField.text = text;

        if (root.rightLinked)
            syncRightDisplay(root.startValue);

    }
    onEndValueChanged: {
        if (root.rightLinked)
            return ;

        var text = formatValue(root.endValue);
        if (rightValueField.text !== text)
            rightValueField.text = text;

    }
    onInterpolationSelectedChanged: {
        if (root.rightLinked) {
            syncRightDisplay(root.startValue);
        } else {
            var text = formatValue(root.endValue);
            if (rightValueField.text !== text)
                rightValueField.text = text;

        }
    }

    // 左側スライダー（ボックスに追従）
    Slider {
        id: leftSlider

        Layout.fillWidth: true
        Layout.preferredWidth: 120
        from: root.minValue
        to: root.maxValue
        enabled: root.enabled
        value: {
            var val = parseFloat(leftValueField.text);
            return isNaN(val) ? root.startValue : val;
        }
        onMoved: {
            var val = decimals === 0 ? Math.round(value) : value;
            root.pushLeftValue(val);
        }
    }

    // 左側数値ボックス（親）
    TextField {
        id: leftValueField

        Layout.preferredWidth: 70
        text: root.formatValue(root.startValue)
        horizontalAlignment: TextInput.AlignHCenter
        selectByMouse: true
        enabled: root.enabled
        onEditingFinished: {
            var newVal = parseFloat(text);
            if (!isNaN(newVal))
                root.pushLeftValue(newVal);

        }

        validator: DoubleValidator {
            decimals: root.decimals
            notation: DoubleValidator.StandardNotation
        }

    }

    // 中央ボタン
    Button {
        id: paramButton

        Layout.preferredWidth: 100
        text: root.paramName
        enabled: root.enabled
        onClicked: root.paramButtonClicked()
    }

    // 右側数値ボックス
    TextField {
        id: rightValueField

        Layout.preferredWidth: 70
        text: root.formatValue(root.rightLinked ? root.startValue : root.endValue)
        horizontalAlignment: TextInput.AlignHCenter
        selectByMouse: true
        enabled: root.rightInteractive
        opacity: root.rightInteractive ? 1 : 0.45
        onEditingFinished: {
            var newVal = parseFloat(text);
            if (!isNaN(newVal))
                root.endValueModified(newVal);

        }

        validator: DoubleValidator {
            decimals: root.decimals
            notation: DoubleValidator.StandardNotation
        }

    }

    // 右側スライダー（ボックスに追従）
    Slider {
        id: rightSlider

        Layout.fillWidth: true
        Layout.preferredWidth: 120
        from: root.minValue
        to: root.maxValue
        enabled: root.rightInteractive
        opacity: root.rightInteractive ? 1 : 0.45
        // ボックスの値をバインディング
        value: {
            var val = parseFloat(rightValueField.text);
            return isNaN(val) ? (root.rightLinked ? root.startValue : root.endValue) : val;
        }
        onMoved: {
            // スライダー操作時はボックスを更新
            var val = decimals === 0 ? Math.round(value) : value;
            rightValueField.text = root.formatValue(val);
            root.endValueModified(val);
        }
    }

}

// ui/qml/common/shaders/blend.glsl
#ifndef AVIQTL_BLEND_GLSL
#define AVIQTL_BLEND_GLSL

// 各ブレンド関数は、base（背景色）と blend（前景色）を受け取り、合成結果を返します。
// アルファ合成は別途行うことを想定しています。

vec3 blendNormal(vec3 base, vec3 blend) {
    return blend;
}

vec3 blendMultiply(vec3 base, vec3 blend) {
    return base * blend;
}

vec3 blendScreen(vec3 base, vec3 blend) {
    return 1.0 - (1.0 - base) * (1.0 - blend);
}

vec3 blendOverlay(vec3 base, vec3 blend) {
    return mix(2.0 * base * blend, 1.0 - 2.0 * (1.0 - base) * (1.0 - blend), step(0.5, base));
}

vec3 blendDarken(vec3 base, vec3 blend) {
    return min(base, blend);
}

vec3 blendLighten(vec3 base, vec3 blend) {
    return max(base, blend);
}

vec3 blendAdd(vec3 base, vec3 blend) {
    return min(base + blend, vec3(1.0));
}

vec3 blendDifference(vec3 base, vec3 blend) {
    return abs(base - blend);
}

#endif

// ui/qml/common/shaders/color.glsl
#ifndef AVIQTL_COLOR_GLSL
#define AVIQTL_COLOR_GLSL

// RGB -> HSV 変換
vec3 rgb2hsv(vec3 c) {
    vec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);
    vec4 p = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));
    vec4 q = mix(vec4(p.xyw, c.r), vec4(c.r, p.yzx), step(p.x, c.r));

    float d = q.x - min(q.w, q.y);
    float e = 1.0e-10;
    return vec3(abs(q.z + (q.w - q.y) / (6.0 * d + e)), d / (q.x + e), q.x);
}

// HSV -> RGB 変換
vec3 hsv2rgb(vec3 c) {
    vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
    vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
    return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
}

// 彩度調整
vec3 adjustSaturation(vec3 color, float saturation) {
    float grey = dot(color, vec3(0.2126, 0.7152, 0.0722));
    return mix(vec3(grey), color, saturation);
}

// コントラスト調整
vec3 adjustContrast(vec3 color, float contrast) {
    return (color - 0.5) * contrast + 0.5;
}

#endif

// ui/qml/common/shaders/math.glsl
#ifndef AVIQTL_MATH_GLSL
#define AVIQTL_MATH_GLSL

const float PI = 3.14159265359;
const float TWO_PI = 6.28318530718;
const float HALF_PI = 1.57079632679;

// 値の範囲変換 (map / remap)
// valueを low1-high1 の範囲から low2-high2 の範囲へ変換
float remap(float value, float low1, float high1, float low2, float high2) {
    return low2 + (value - low1) * (high2 - low2) / (high1 - low1);
}

// ステップ関数（エッジを滑らかにする）
float smoothStepInOut(float low, float high, float value) {
    float t = clamp((value - low) / (high - low), 0.0, 1.0);
    return t * t * (3.0 - 2.0 * t);
}

// 輝度計算 (Rec.709)
float luminance(vec3 color) {
    return dot(color, vec3(0.2126, 0.7152, 0.0722));
}

// 2D回転行列
mat2 rotate2d(float angle) {
    return mat2(cos(angle), -sin(angle),
                sin(angle),  cos(angle));
}

// UV座標を中心基準にスケーリング
vec2 scaleUV(vec2 uv, vec2 scale, vec2 center) {
    return (uv - center) / scale + center;
}

#endif

// ui/qml/common/shaders/noise.glsl
#ifndef AVIQTL_NOISE_GLSL
#define AVIQTL_NOISE_GLSL

// 簡易乱数 (0.0 - 1.0)
float random(vec2 st) {
    return fract(sin(dot(st.xy, vec2(12.9898, 78.233))) * 43758.5453123);
}

// 2Dノイズ (Value Noise) - ブロック状のノイズや雲模様の基礎
float noise(vec2 st) {
    vec2 i = floor(st);
    vec2 f = fract(st);

    // Four corners in 2D of a tile
    float a = random(i);
    float b = random(i + vec2(1.0, 0.0));
    float c = random(i + vec2(0.0, 1.0));
    float d = random(i + vec2(1.0, 1.0));

    // Smooth Interpolation
    vec2 u = f * f * (3.0 - 2.0 * f);

    return mix(a, b, u.x) +
            (c - a)* u.y * (1.0 - u.x) +
            (d - b) * u.x * u.y;
}

// フラクタルブラウン運動 (FBM) - より自然な雲や地形のようなノイズ
float fbm(vec2 st) {
    float value = 0.0;
    float amplitude = 0.5;
    float frequency = 0.0;

    for (int i = 0; i < 5; i++) {
        value += amplitude * noise(st);
        st *= 2.0;
        amplitude *= 0.5;
    }
    return value;
}

#endif

