    int effectIndex = static_cast<int>(luaL_checkinteger(L, 2));
    const char *key = luaL_checkstring(L, 3);
    QVariant val;
    if (lua_type(L, 4) == LUA_TNUMBER) {
        val = lua_tonumber(L, 4);
