#ifndef GLTFIO_NODEMANAGER_H
#define GLTFIO_NODEMANAGER_H

#include <filament/FilamentAPI.h>

#include <utils/bitset.h>
#include <utils/compiler.h>
#include <utils/CString.h>
#include <utils/EntityInstance.h>
