    RGBA_ASTC_8x6, // [79]
    RGBA_ASTC_8x8, // [80]
    RGBA_ASTC_10x5, // [81]
    RGBA_ASTC_10x6, // [82]
    RGBA_ASTC_10x8, // [83]
